'use client'

import Image from 'next/image'
import Link from 'next/link'
import { notFound } from 'next/navigation'
import { use, useState, useEffect, useCallback } from 'react'
import { 
  Users, 
  Mail, 
  Phone, 
  ChevronLeft, 
  Loader2
} from 'lucide-react'

interface TeamMember {
  id: string
  name: string
  role: string
  bio?: string
  image?: string
  email?: string
  phone?: string
  department?: string
  order_index: number
  is_active: boolean
}

// Hardcoded ministry team configs for navigation and meta
const ministryTeams = [
  { name: 'Worship Team', slug: 'worship-team', description: 'Leading our congregation in worship through music and praise', icon: '🎵' },
  { name: 'Media & Technology', slug: 'media-technology', description: 'Managing audio, video, and livestream for our services', icon: '🎥' },
  { name: 'Ushering Team', slug: 'ushering-team', description: 'Welcoming and guiding visitors and members during services', icon: '🚪' },
  { name: 'Security Team', slug: 'security-team', description: 'Ensuring a safe environment for all attendees', icon: '🛡️' },
  { name: 'Intercessory Prayer Team', slug: 'intercessory-prayer-team', description: 'Praying for the church, community, and world', icon: '🙏' },
  { name: 'Greeters Team', slug: 'greeters-team', description: 'Making everyone feel welcome as they arrive', icon: '👋' }
]



export default function DepartmentTeamPage({ params }: { params: Promise<{ department: string }> }) {
  const resolvedParams = use(params)
  const { department } = resolvedParams
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  const teamConfig = ministryTeams.find(t => t.slug === department)
  if (!teamConfig) {
    notFound()
  }

  const fetchTeamMembers = useCallback(async () => {
    try {
      const baseUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3000'
      const url = new URL(`${baseUrl}/api/teams`)
      url.searchParams.append('department', teamConfig!.name)
      url.searchParams.append('limit', '50')
      url.searchParams.append('is_active', 'true')

      const res = await fetch(url, { cache: 'no-store' })

      if (!res.ok) {
        throw new Error('Failed to fetch team members')
      }

      const data = await res.json()
      if (data.teamMembers) {
        // Sort by order_index
        const sorted = [...data.teamMembers].sort((a, b) => (a.order_index || 0) - (b.order_index || 0))
        setTeamMembers(sorted)
      }
    } catch (err) {
      console.error('Error fetching team members:', err)
      setError('Failed to load team members')
    } finally {
      setLoading(false)
    }
  }, [department])

  useEffect(() => {
    fetchTeamMembers()
  }, [department])



  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-primary to-secondary text-white py-16">
        <div className="container mx-auto px-4">
          <Link 
            href="/about/team" 
            className="inline-flex items-center text-gray-300 hover:text-white mb-6 transition duration-300"
          >
            <ChevronLeft className="h-4 w-4 mr-2" />
            Back to Teams
          </Link>
          <div className="text-4xl md:text-5xl font-bold mb-4 flex items-center">
            <span className="text-5xl mr-4">{teamConfig!.icon}</span>
            {teamConfig!.name}
          </div>
          <p className="text-xl text-gray-200 max-w-3xl">
            {teamConfig!.description}
          </p>
        </div>
      </section>

      {/* Team Members */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          <div className="max-w-6xl mx-auto">
            <div className="text-center mb-12">
              <Users className="h-12 w-12 text-accent mx-auto mb-4" />
              <h2 className="text-4xl font-bold mb-4">Team Members</h2>
              <p className="text-gray-600 text-lg max-w-3xl mx-auto">
                Meet the dedicated individuals serving in the {teamConfig!.name}
              </p>
            </div>

            {loading && (
              <div className="flex justify-center items-center py-20">
                <Loader2 className="h-8 w-8 animate-spin text-accent" />
                <span className="ml-2 text-gray-600">Loading team members...</span>
              </div>
            )}

            {error && (
              <div className="text-center py-20">
                <p className="text-red-600 mb-4">{error}</p>
                <p className="text-gray-600">No team members found for this department yet.</p>
              </div>
            )}

            {!loading && !error && teamMembers.length === 0 && (
              <div className="text-center py-20">
                <Users className="h-16 w-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-2xl font-bold text-gray-500 mb-2">No Team Members Yet</h3>
                <p className="text-gray-600 max-w-md mx-auto">
                  This team is growing. Check back soon for leadership and members.
                </p>
              </div>
            )}

            {!loading && teamMembers.length > 0 && (
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {teamMembers.map((member, index) => (
                  <div 
                    key={member.id || index.toString()} 
                    className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-xl transition duration-300"
                  >
                    <div className="bg-gray-200 h-64 flex items-center justify-center relative">
                      {member.image ? (
                        <Image
                          src={member.image}
                          alt={member.name}
                          fill
                          className="object-cover"
                        />
                      ) : (
                        <div className="text-center p-8">
                          <div className="w-32 h-32 bg-accent/10 rounded-full flex items-center justify-center mx-auto mb-4">
                            <span className="text-3xl font-bold text-accent">
                              {member.name.split(' ').map(n => n[0]).join('')}
                            </span>
                          </div>
                        </div>
                      )}
                    </div>

                    <div className="p-6">
                      <h3 className="text-xl font-bold mb-1">{member.name}</h3>
                      <p className="text-accent font-medium mb-4">{member.role}</p>

                      {member.bio && (
                        <p className="text-gray-600 text-sm mb-4 line-clamp-3">
                          {member.bio}
                        </p>
                      )}

                      <div className="space-y-2 pt-4 border-t">
                        {member.email && (
                          <a 
                            href={`mailto:${member.email}`}
                            className="flex items-center text-sm text-gray-600 hover:text-accent transition duration-300"
                          >
                            <Mail className="h-4 w-4 mr-2" />
                            {member.email}
                          </a>
                        )}
                        {member.phone && (
                          <a 
                            href={`tel:${member.phone}`}
                            className="flex items-center text-sm text-gray-600 hover:text-accent transition duration-300"
                          >
                            <Phone className="h-4 w-4 mr-2" />
                            {member.phone}
                          </a>
                        )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { 
  Calendar, 
  Plus, 
  Edit, 
  Trash2, 
  Upload,
  ChevronLeft,
  ChevronRight,
  X,
  Check,
  AlertCircle,
  Loader2,
  RefreshCw
} from 'lucide-react'

interface CalendarEvent {
  _id: string
  title: string
  description: string
  date: string
  time: string
  endDate?: string
  endTime?: string
  location: string
  category: 'holiday' | 'special' | 'revival'
  year: number
  recurring: boolean
  colorCode?: string
}

const categories = [
  { id: 'holiday', label: 'Public Holiday', color: 'bg-blue-500' },
  { id: 'special', label: 'Special Program', color: 'bg-green-500' },
  { id: 'revival', label: 'Revival Week', color: 'bg-orange-500' }
]

// Generate years from 2020 to 2099
const years = Array.from({ length: 80 }, (_, i) => 2020 + i)

export default function AdminCalendarPage() {
  const [events, setEvents] = useState<CalendarEvent[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const [deletingId, setDeletingId] = useState<string | null>(null)

  const [selectedYear, setSelectedYear] = useState(new Date().getFullYear())
  const [selectedCategory, setSelectedCategory] = useState('all')

  const [showModal, setShowModal] = useState(false)
  const [showImportModal, setShowImportModal] = useState(false)
  const [editingEvent, setEditingEvent] = useState<CalendarEvent | null>(null)

  const [formData, setFormData] = useState({
    title: '',
    description: '',
    date: '',
    time: 'All Day',
    endDate: '',
    endTime: '',
    location: 'Church Premises',
    category: 'special' as 'holiday' | 'special' | 'revival',
    recurring: false,
    colorCode: '#3B82F6'
  })

  const [csvData, setCsvData] = useState('')
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Fetch events
  const fetchEvents = async () => {
    setLoading(true)
    setError('')

    try {
      const params = new URLSearchParams({ year: selectedYear.toString() })
      if (selectedCategory !== 'all') {
        params.append('category', selectedCategory)
      }

      const response = await fetch(`/api/calendar?${params}`)
      const data = await response.json()

      if (data.success) {
        setEvents(data.events)
      } else {
        setError(data.error || 'Failed to fetch events')
      }
    } catch (err) {
      setError('Failed to connect to server')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchEvents()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedYear, selectedCategory])

  // Reset form
  const resetForm = () => {
    setFormData({
      title: '',
      description: '',
      date: '',
      time: 'All Day',
      endDate: '',
      endTime: '',
      location: 'Church Premises',
      category: 'special',
      recurring: false,
      colorCode: '#3B82F6'
    })
    setEditingEvent(null)
  }

  // Open modal for new event
  const openNewEventModal = () => {
    resetForm()
    setShowModal(true)
  }

  // Open modal for editing
  const openEditModal = (event: CalendarEvent) => {
    setEditingEvent(event)
    setFormData({
      title: event.title,
      description: event.description || '',
      date: event.date,
      time: event.time,
      endDate: event.endDate || '',
      endTime: event.endTime || '',
      location: event.location,
      category: event.category,
      recurring: event.recurring,
      colorCode: event.colorCode || '#3B82F6'
    })
    setShowModal(true)
  }

  // Submit form
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')
    setSuccess('')

    try {
      const url = editingEvent 
        ? `/api/calendar?id=${editingEvent._id}`
        : '/api/calendar'

      const response = await fetch(url, {
        method: editingEvent ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...formData,
          year: selectedYear
        })
      })

      const data = await response.json()

      if (data.success) {
        setSuccess(editingEvent ? 'Event updated successfully' : 'Event created successfully')
        setShowModal(false)
        resetForm()
        fetchEvents()
      } else {
        setError(data.error || 'Failed to save event')
      }
    } catch (err) {
      setError('Failed to save event')
    }
  }

  // Delete event
  const handleDelete = async (eventId: string) => {
    if (!confirm('Are you sure you want to delete this event?')) return

    setDeletingId(eventId)
    setError('')

    try {
      const response = await fetch(`/api/calendar?id=${eventId}`, {
        method: 'DELETE'
      })

      const data = await response.json()

      if (data.success) {
        alert('Event deleted successfully!')
        fetchEvents()
      } else {
        alert(data.error || 'Failed to delete event')
      }
    } catch (err) {
      console.error('Delete error:', err)
      alert('An error occurred while deleting')
    } finally {
      setDeletingId(null)
    }
  }

  // Delete all events for a year
  const handleDeleteAll = async () => {
    if (!confirm(`Are you sure you want to delete ALL events for ${selectedYear}? This cannot be undone!`)) return

    setError('')

    try {
      const response = await fetch(`/api/calendar?year=${selectedYear}`, {
        method: 'DELETE'
      })

      const data = await response.json()

      if (data.success) {
        alert(`${data.count} events deleted successfully!`)
        fetchEvents()
      } else {
        alert(data.error || 'Failed to delete events')
      }
    } catch (err) {
      console.error('Delete error:', err)
      alert('An error occurred while deleting')
    }
  }

  // Handle CSV import
  const handleCsvImport = async () => {
    if (!csvData.trim()) {
      setError('Please paste CSV data first')
      return
    }

    setError('')
    setSuccess('')

    try {
      // Parse CSV
      const lines = csvData.trim().split('\n')
      const headers = lines[0].split(',').map(h => h.trim().toLowerCase())

      const events = []
      for (let i = 1; i < lines.length; i++) {
        const values = lines[i].split(',').map(v => v.trim())
        if (values.length >= 2) {
          const event: Record<string, unknown> = {
            title: values[0],
            date: values[1],
            time: values[2] || 'All Day',
            location: values[3] || 'Church Premises',
            category: values[4] || 'special',
            year: selectedYear
          }
          events.push(event)
        }
      }

      const response = await fetch('/api/calendar', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(events)
      })

      const data = await response.json()

      if (data.success) {
        setSuccess(`${data.count} events imported successfully`)
        setShowImportModal(false)
        setCsvData('')
        fetchEvents()
      } else {
        setError(data.error || 'Failed to import events')
      }
    } catch (err) {
      setError('Failed to import CSV data')
    }
  }

  // Get category color
  const getCategoryColor = (category: string) => {
    const cat = categories.find(c => c.id === category)
    return cat ? cat.color : 'bg-gray-500'
  }

  // Format date
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr)
    return date.toLocaleDateString('en-US', { 
      weekday: 'short',
      month: 'short', 
      day: 'numeric',
      year: 'numeric' 
    })
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-gradient-to-r from-primary to-secondary text-white py-6">
        <div className="container mx-auto px-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold">Calendar Management</h1>
              <p className="opacity-90 mt-1">Manage church calendar events</p>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => setShowImportModal(true)}
                className="flex items-center gap-2 bg-white/20 hover:bg-white/30 px-4 py-2 rounded-lg transition"
              >
                <Upload className="h-4 w-4" />
                Import CSV
              </button>
              <button
                onClick={openNewEventModal}
                className="flex items-center gap-2 bg-accent hover:bg-red-700 px-4 py-2 rounded-lg transition"
              >
                <Plus className="h-4 w-4" />
                Add Event
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Controls */}
      <div className="bg-white shadow-sm border-b">
        <div className="container mx-auto px-4 py-4">
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center gap-4">
              {/* Year Selector */}
              <div className="flex items-center gap-2">
                <button
                  onClick={() => setSelectedYear(prev => prev - 1)}
                  className="p-2 hover:bg-gray-100 rounded-lg transition"
                >
                  <ChevronLeft className="h-4 w-4" />
                </button>
                <select
                  value={selectedYear}
                  onChange={(e) => setSelectedYear(parseInt(e.target.value))}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                >
                  {years.map(year => (
                    <option key={year} value={year}>{year}</option>
                  ))}
                </select>
                <button
                  onClick={() => setSelectedYear(prev => prev + 1)}
                  className="p-2 hover:bg-gray-100 rounded-lg transition"
                >
                  <ChevronRight className="h-4 w-4" />
                </button>
              </div>

              {/* Category Filter */}
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
              >
                <option value="all">All Categories</option>
                {categories.map(cat => (
                  <option key={cat.id} value={cat.id}>{cat.label}</option>
                ))}
              </select>
            </div>

            <div className="flex items-center gap-3">
              <button
                onClick={fetchEvents}
                className="p-2 hover:bg-gray-100 rounded-lg transition"
                title="Refresh"
              >
                <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
              </button>

              {events.length > 0 && (
                <button
                  onClick={handleDeleteAll}
                  className="flex items-center gap-2 text-red-500 hover:text-red-700 px-3 py-2 rounded-lg hover:bg-red-50 transition"
                >
                  <Trash2 className="h-4 w-4" />
                  Delete All {selectedYear}
                </button>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Success/Error Messages */}
      {success && (
        <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 mx-4 mt-4 rounded-lg flex items-center">
          <Check className="h-4 w-4 mr-2" />
          {success}
        </div>
      )}

      {error && (
        <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 mx-4 mt-4 rounded-lg flex items-center">
          <AlertCircle className="h-4 w-4 mr-2" />
          {error}
        </div>
      )}

      {/* Events Grid */}
      <div className="container mx-auto px-4 py-8">
        {loading ? (
          <div className="flex items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-accent" />
          </div>
        ) : events.length === 0 ? (
          <div className="text-center py-12 bg-white rounded-xl shadow">
            <Calendar className="h-16 w-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-xl font-bold mb-2 text-gray-600">No Events Found</h3>
            <p className="text-gray-500 mb-4">
              {selectedCategory !== 'all' 
                ? `No ${categories.find(c => c.id === selectedCategory)?.label} events for ${selectedYear}`
                : `No calendar events for ${selectedYear}`
              }
            </p>
            <button
              onClick={openNewEventModal}
              className="inline-flex items-center gap-2 bg-accent text-white px-4 py-2 rounded-lg hover:bg-red-700 transition"
            >
              <Plus className="h-4 w-4" />
              Add First Event
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {events.map((event) => (
              <div
                key={event._id}
                className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-xl transition duration-300"
              >
                <div className={`h-2 ${getCategoryColor(event.category)}`} />
                <div className="p-5">
                  <div className="flex items-start justify-between mb-3">
                    <span className={`inline-block px-2 py-1 rounded-full text-xs font-medium text-white ${getCategoryColor(event.category)}`}>
                      {categories.find(c => c.id === event.category)?.label}
                    </span>
                    <div className="flex gap-1">
                      <button
                        onClick={() => openEditModal(event)}
                        className="p-1.5 text-gray-400 hover:text-accent hover:bg-gray-100 rounded transition"
                      >
                        <Edit className="h-4 w-4" />
                      </button>
                      <button
                        onClick={() => handleDelete(event._id)}
                        className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-gray-100 rounded transition"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </div>
                  </div>

                  <h3 className="text-lg font-bold text-gray-800 mb-2">{event.title}</h3>

                  <div className="space-y-2 text-sm text-gray-600">
                    <div className="flex items-center gap-2">
                      <Calendar className="h-4 w-4 text-gray-400" />
                      <span>{formatDate(event.date)}</span>
                    </div>
                    {event.time !== 'All Day' && (
                      <div className="flex items-center gap-2">
                        <span className="h-4 w-4 text-gray-400" />
                        <span>{event.time}</span>
                      </div>
                    )}
                    <div className="flex items-center gap-2">
                      <span className="h-4 w-4 text-gray-400" />
                      <span>{event.location}</span>
                    </div>
                  </div>

                  {event.description && (
                    <p className="text-sm text-gray-500 mt-3 line-clamp-2">
                      {event.description}
                    </p>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Add/Edit Event Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div className="fixed inset-0 bg-black/50 backdrop-blur-md" />
          {/* Modal content */}
          <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold">
                  {editingEvent ? 'Edit Event' : 'Add New Event'}
                </h2>
                <button
                  onClick={() => {
                    setShowModal(false)
                    resetForm()
                  }}
                  className="p-2 hover:bg-gray-100 rounded-lg transition"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>

              <form onSubmit={handleSubmit} className="space-y-4">
                {/* Title */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Event Title *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    placeholder="e.g., Power Conference"
                  />
                </div>

                {/* Date */}
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Start Date *
                    </label>
                    <input
                      type="date"
                      required
                      value={formData.date}
                      onChange={(e) => setFormData({ ...formData, date: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Time
                    </label>
                    <input
                      type="text"
                      value={formData.time}
                      onChange={(e) => setFormData({ ...formData, time: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                      placeholder="All Day"
                    />
                  </div>
                </div>

                {/* End Date */}
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      End Date
                    </label>
                    <input
                      type="date"
                      value={formData.endDate}
                      onChange={(e) => setFormData({ ...formData, endDate: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      End Time
                    </label>
                    <input
                      type="text"
                      value={formData.endTime}
                      onChange={(e) => setFormData({ ...formData, endTime: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    />
                  </div>
                </div>

                {/* Category & Location */}
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Category *
                    </label>
                    <select
                      required
                      value={formData.category}
                      onChange={(e) => {
                        const cat = e.target.value as 'holiday' | 'special' | 'revival'
                        setFormData({ ...formData, category: cat })
                      }}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    >
                      {categories.map(cat => (
                        <option key={cat.id} value={cat.id}>{cat.label}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">
                      Location
                    </label>
                    <input
                      type="text"
                      value={formData.location}
                      onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                      className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    />
                  </div>
                </div>

                {/* Description */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Description
                  </label>
                  <textarea
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                    rows={3}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent"
                    placeholder="Brief description of the event..."
                  />
                </div>

                {/* Actions */}
                <div className="flex justify-end gap-3 pt-4 border-t">
                  <button
                    type="button"
                    onClick={() => {
                      setShowModal(false)
                      resetForm()
                    }}
                    className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    className="px-6 py-2 bg-accent text-white rounded-lg hover:bg-red-700 transition"
                  >
                    {editingEvent ? 'Update Event' : 'Create Event'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Import CSV Modal */}
      {showImportModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div className="fixed inset-0 bg-black/50 backdrop-blur-md" />
          {/* Modal content */}
          <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-bold">Import Events from CSV</h2>
                <button
                  onClick={() => setShowImportModal(false)}
                  className="p-2 hover:bg-gray-100 rounded-lg transition"
                >
                  <X className="h-5 w-5" />
                </button>
              </div>

              <div className="space-y-4">
                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                  <h4 className="font-semibold text-blue-800 mb-2">CSV Format:</h4>
                  <code className="text-xs text-blue-600 block">
                    title,date,time,location,category
                  </code>
                  <p className="text-xs text-blue-600 mt-2">
                    Example: Power Conference,2026-05-25,All Day,Church Premises,special
                  </p>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Paste CSV Data
                  </label>
                  <textarea
                    value={csvData}
                    onChange={(e) => setCsvData(e.target.value)}
                    rows={10}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent font-mono text-sm"
                    placeholder="title,date,time,location,category&#10;Power Conference,2026-05-25,All Day,Church Premises,special&#10;New Year's Day,2026-01-01,All Day,National Holiday,holiday"
                  />
                </div>

                <div className="flex justify-end gap-3 pt-4 border-t">
                  <button
                    type="button"
                    onClick={() => setShowImportModal(false)}
                    className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={handleCsvImport}
                    className="px-6 py-2 bg-accent text-white rounded-lg hover:bg-red-700 transition"
                  >
                    Import Events
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client';

import { useState, useEffect } from 'react';
import { 
  Plus, 
  Search, 
  Users, 
  Trash2, 
  Edit,
  Mail,
  Phone,
  Loader2,
  X,
  Star,
  Globe,
  MapPin
} from 'lucide-react';
import Image from 'next/image'
import ImageUpload from '@/components/ImageUpload';

interface Counsellor {
  id: string;
  name: string;
  title: string;
  specialization: string[];
  bio: string;
  imageUrl: string;
  email: string;
  phone?: string;
  availability: Availability[];
  isOnline: boolean;
  isInPerson: boolean;
  yearsOfExperience: number;
  rating: number;
  reviewCount: number;
  isActive: boolean;
  createdAt?: string;
  updatedAt?: string;
}

interface Availability {
  dayOfWeek: number;
  startTime: string;
  endTime: string;
}

const DAYS_OF_WEEK = [
  { value: 0, label: 'Sunday' },
  { value: 1, label: 'Monday' },
  { value: 2, label: 'Tuesday' },
  { value: 3, label: 'Wednesday' },
  { value: 4, label: 'Thursday' },
  { value: 5, label: 'Friday' },
  { value: 6, label: 'Saturday' },
];

import { TOPICS } from '@/types/counselling';

export default function CounsellingAdminPage() {
  const [counsellors, setCounsellors] = useState<Counsellor[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [editingCounsellor, setEditingCounsellor] = useState<Counsellor | null>(null);
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 10,
    total: 0,
    totalPages: 0
  });
  const [formData, setFormData] = useState({
    name: '',
    title: '',
    bio: '',
    email: '',
    phone: '',
    specialization: [] as string[],
    imageUrl: '',
    isOnline: true,
    isInPerson: true,
    yearsOfExperience: 0,
    availability: [] as Availability[]
  });
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [modalMode, setModalMode] = useState<'create' | 'edit'>('create');

  const [showAll, setShowAll] = useState(false);

  const fetchCounsellors = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.append('page', pagination.page.toString());
      params.append('limit', pagination.limit.toString());
      if (showAll) params.append('includeInactive', 'true');

      const response = await fetch(`/api/counsellors?${params.toString()}`);
      const data = await response.json();

      if (data.success) {
        setCounsellors(data.data.counsellors);
        setPagination(prev => ({
          ...prev,
          total: data.data.total,
          totalPages: Math.ceil(data.data.total / pagination.limit)
        }));
      }
    } catch (err) {
      console.error('Error fetching counselors:', err);
      setError('Failed to load counselors');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCounsellors();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pagination.page, showAll]);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setPagination(prev => ({ ...prev, page: 1 }));
    fetchCounsellors();
  };

  const openCreateModal = () => {
    setModalMode('create');
    setFormData({
      name: '',
      title: '',
      bio: '',
      email: '',
      phone: '',
      specialization: [],
      imageUrl: '',
      isOnline: true,
      isInPerson: true,
      yearsOfExperience: 0,
      availability: []
    });
    setEditingCounsellor(null);
    setError('');
    setSuccess('');
    setShowCreateModal(true);
  };

  const openEditModal = (counsellor: Counsellor) => {
    setModalMode('edit');
    setEditingCounsellor(counsellor);
    setFormData({
      name: counsellor.name,
      title: counsellor.title,
      bio: counsellor.bio,
      email: counsellor.email,
      phone: counsellor.phone || '',
      specialization: counsellor.specialization,
      imageUrl: counsellor.imageUrl,
      isOnline: counsellor.isOnline,
      isInPerson: counsellor.isInPerson,
      yearsOfExperience: counsellor.yearsOfExperience,
      availability: counsellor.availability
    });
    setError('');
    setSuccess('');
    setShowCreateModal(true);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    setUploading(true);
    setError('');
    setSuccess('');

    try {
      const response = await fetch('/api/counsellors', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (data.success) {
        setSuccess('Counsellor added successfully!');
        setShowCreateModal(false);
        setFormData({
          name: '',
          title: '',
          bio: '',
          email: '',
          phone: '',
          specialization: [],
          imageUrl: '',
          isOnline: true,
          isInPerson: true,
          yearsOfExperience: 0,
          availability: []
        });
        fetchCounsellors();
      } else {
        setError(data.error || 'Failed to add counsellor');
      }
    } catch (err) {
      setError('An error occurred while adding counsellor');
    } finally {
      setUploading(false);
    }
  };

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingCounsellor) return;

    setUploading(true);
    setError('');
    setSuccess('');

    try {
      const response = await fetch(`/api/counsellors?id=${editingCounsellor.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (data.success) {
        setSuccess('Counsellor updated successfully!');
        setShowCreateModal(false);
        setEditingCounsellor(null);
        fetchCounsellors();
      } else {
        setError(data.error || 'Failed to update counsellor');
      }
    } catch (err) {
      setError('An error occurred while updating counsellor');
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this counsellor?')) return;

    setDeletingId(id);
    try {
      const response = await fetch(`/api/counsellors?id=${id}`, {
        method: 'DELETE'
      });
      const data = await response.json();

      if (data.success) {
        alert('Counsellor deleted successfully!');
        fetchCounsellors();
      } else {
        alert(data.error || 'Failed to delete counsellor');
      }
    } catch (err) {
      console.error('Delete error:', err);
      alert('An error occurred while deleting');
    } finally {
      setDeletingId(null);
    }
  };

  const addAvailabilitySlot = () => {
    setFormData(prev => ({
      ...prev,
      availability: [
        ...prev.availability,
        { dayOfWeek: 1, startTime: '09:00', endTime: '17:00' }
      ]
    }));
  };

  const removeAvailabilitySlot = (index: number) => {
    setFormData(prev => ({
      ...prev,
      availability: prev.availability.filter((_, i) => i !== index)
    }));
  };

  const updateAvailabilitySlot = (index: number, field: keyof Availability, value: string | number) => {
    setFormData(prev => ({
      ...prev,
      availability: prev.availability.map((slot, i) => 
        i === index ? { ...slot, [field]: value } : slot
      )
    }));
  };

  const toggleSpecialization = (spec: string) => {
    setFormData(prev => ({
      ...prev,
      specialization: prev.specialization.includes(spec)
        ? prev.specialization.filter(s => s !== spec)
        : [...prev.specialization, spec]
    }));
  };

  const filteredCounsellors = search
    ? counsellors.filter(c => 
        c.name.toLowerCase().includes(search.toLowerCase()) ||
        c.title.toLowerCase().includes(search.toLowerCase()) ||
        c.specialization.some(s => s.toLowerCase().includes(search.toLowerCase()))
      )
    : counsellors;

  return (
    <div>
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div className="flex items-center space-x-4">
          <form onSubmit={handleSearch} className="flex items-center space-x-4">
            <div className="relative">
              <Search className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
              <input
                type="text"
                placeholder="Search counselors..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent w-64"
              />
            </div>
            <label className="flex items-center space-x-2">
              <input
                type="checkbox"
                checked={showAll}
                onChange={(e) => {
                  setShowAll(e.target.checked);
                  setPagination(prev => ({ ...prev, page: 1 }));
                }}
                className="h-4 w-4 text-accent focus:ring-accent border-gray-300 rounded"
              />
              <span className="text-sm text-gray-600">Show inactive</span>
            </label>
            <button
              type="submit"
              className="px-4 py-2 bg-accent text-white rounded-lg hover:bg-red-700 transition duration-300"
            >
              Search
            </button>
          </form>
        </div>
        <button
          onClick={openCreateModal}
          className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition duration-300"
        >
          <Plus className="h-5 w-5 mr-2" />
          Add Counsellor
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white p-4 rounded-lg shadow">
          <p className="text-gray-600 text-sm">Total Counsellors</p>
          <p className="text-2xl font-bold">{pagination.total}</p>
        </div>
        <div className="bg-white p-4 rounded-lg shadow">
          <p className="text-gray-600 text-sm">Active</p>
          <p className="text-2xl font-bold text-green-500">
            {counsellors.filter(c => c.isActive).length}
          </p>
        </div>
        <div className="bg-white p-4 rounded-lg shadow">
          <p className="text-gray-600 text-sm">Online Sessions</p>
          <p className="text-2xl font-bold text-blue-500">
            {counsellors.filter(c => c.isOnline).length}
          </p>
        </div>
        <div className="bg-white p-4 rounded-lg shadow">
          <p className="text-gray-600 text-sm">In-Person</p>
          <p className="text-2xl font-bold text-purple-500">
            {counsellors.filter(c => c.isInPerson).length}
          </p>
        </div>
      </div>

      {/* Loading */}
      {loading && (
        <div className="flex justify-center items-center py-20">
          <Loader2 className="h-8 w-8 animate-spin text-accent" />
          <span className="ml-2 text-gray-600">Loading counselors...</span>
        </div>
      )}

      {/* Counsellors Grid */}
      {!loading && (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredCounsellors.map((counsellor) => (
              <div 
                key={counsellor.id} 
                className={`bg-white rounded-lg shadow overflow-hidden hover:shadow-lg transition duration-300 ${!counsellor.isActive ? 'opacity-60' : ''}`}
              >
                {/* Image */}
                <div className="h-48 bg-gray-200 flex items-center justify-center relative">
                  {counsellor.imageUrl ? (
                      <Image 
                      src={counsellor.imageUrl} 
                      alt={counsellor.name}
                      fill
                      className="object-cover"
                    />
                  ) : (
                    <Users className="h-16 w-16 text-gray-400" />
                  )}
                  {!counsellor.isActive && (
                    <div className="absolute top-2 left-2 bg-red-500 text-white px-2 py-1 rounded text-xs">
                      Inactive
                    </div>
                  )}
                </div>

                {/* Info */}
                <div className="p-4">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-bold text-gray-800">{counsellor.name}</h3>
                    <div className="flex items-center">
                      <Star className="h-4 w-4 text-yellow-500 fill-yellow-500 mr-1" />
                      <span className="text-sm font-medium">{counsellor.rating}</span>
                    </div>
                  </div>

                  <p className="text-accent font-medium mb-2">{counsellor.title}</p>

                  <div className="flex gap-2 mb-3">
                    {counsellor.isOnline && (
                      <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded flex items-center">
                        <Globe className="h-3 w-3 mr-1" /> Online
                      </span>
                    )}
                    {counsellor.isInPerson && (
                      <span className="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded flex items-center">
                        <MapPin className="h-3 w-3 mr-1" /> In-Person
                      </span>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-1 mb-3">
                    {counsellor.specialization.slice(0, 3).map((spec) => (
                      <span key={spec} className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded">
                        {spec}
                      </span>
                    ))}
                    {counsellor.specialization.length > 3 && (
                      <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded">
                        +{counsellor.specialization.length - 3}
                      </span>
                    )}
                  </div>

                  <p className="text-gray-600 text-sm line-clamp-2 mb-4">{counsellor.bio}</p>

                  <div className="space-y-2 text-sm text-gray-500">
                    {counsellor.email && (
                      <div className="flex items-center">
                        <Mail className="h-4 w-4 mr-2" />
                        <span className="truncate">{counsellor.email}</span>
                      </div>
                    )}
                    {counsellor.phone && (
                      <div className="flex items-center">
                        <Phone className="h-4 w-4 mr-2" />
                        <span>{counsellor.phone}</span>
                      </div>
                    )}
                  </div>

                  {/* Actions */}
                  <div className="flex justify-between mt-4 pt-4 border-t">
                    <button
                      onClick={() => handleDelete(counsellor.id)}
                      disabled={deletingId === counsellor.id}
                      className="flex items-center text-red-500 hover:text-red-700 disabled:opacity-50"
                    >
                      {deletingId === counsellor.id ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                      ) : (
                        <>
                          <Trash2 className="h-4 w-4 mr-1" />
                          Delete
                        </>
                      )}
                    </button>
                    <button
                      onClick={() => openEditModal(counsellor)}
                      className="flex items-center text-accent hover:text-red-600"
                    >
                      <Edit className="h-4 w-4 mr-1" />
                      Edit
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Empty State */}
          {filteredCounsellors.length === 0 && (
            <div className="text-center py-20 bg-white rounded-lg shadow">
              <Users className="h-16 w-16 text-gray-300 mx-auto mb-4" />
              <h3 className="text-xl font-bold mb-2">No counselors found</h3>
              <p className="text-gray-600 mb-4">
                {search 
                  ? 'Try adjusting your search'
                  : 'Add your first counsellor to get started'}
              </p>
              <button
                onClick={openCreateModal}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition duration-300 inline-flex items-center"
              >
                <Plus className="h-5 w-5 mr-2" />
                Add Counsellor
              </button>
            </div>
          )}
        </>
      )}

      {/* Create/Edit Modal */}
      {showCreateModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div className="fixed inset-0 bg-black/50 backdrop-blur-md" onClick={() => setShowCreateModal(false)} />
          {/* Modal content */}
          <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center p-4 border-b sticky top-0 bg-white">
              <h2 className="text-xl font-bold">
                {modalMode === 'create' ? 'Add Counsellor' : 'Edit Counsellor'}
              </h2>
              <button
                onClick={() => setShowCreateModal(false)}
                className="text-gray-500 hover:text-gray-700"
              >
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={modalMode === 'create' ? handleCreate : handleUpdate} className="p-4">
              {/* Error/Success Messages */}
              {error && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 rounded-lg">
                  {error}
                </div>
              )}

              {success && (
                <div className="mb-4 p-3 bg-green-50 border border-green-200 text-green-700 rounded-lg">
                  {success}
                </div>
              )}

              {/* Name */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Full Name *
                </label>
                <input
                  type="text"
                  required
                  value={formData.name}
                  onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                  placeholder="Enter full name"
                />
              </div>

              {/* Title */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Title/Position *
                </label>
                <input
                  type="text"
                  required
                  value={formData.title}
                  onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                  placeholder="e.g., Senior Pastoral Counsellor"
                />
              </div>

              {/* Bio */}
              <div className="mb-4">
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Bio *
                </label>
                <textarea
                  required
                  value={formData.bio}
                  onChange={(e) => setFormData(prev => ({ ...prev, bio: e.target.value }))}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                  rows={3}
                  placeholder="Brief biography..."
                />
              </div>

              {/* Email & Phone */}
              <div className="grid grid-cols-2 gap-4 mb-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Email *
                  </label>
                  <input
                    type="email"
