              </p>
              <Link
                href="/admin/sermons/upload"
                className="px-4 py-2 bg-accent text-white rounded-lg hover:bg-red-700 transition duration-300 inline-flex items-center"
              >
                <Upload className="h-5 w-5 mr-2" />
                Upload Sermon
              </Link>
            </div>
          )}

          {/* Pagination with Previous/Next buttons */}
          {pagination.totalPages > 1 && (
            <div className="flex flex-col items-center mt-12 space-y-4">
              {/* Previous/Next Buttons with << and >> icons */}
              <div className="flex items-center space-x-4">
                <button
                  type="button"
                  onClick={(e) => { e.preventDefault(); setPagination(prev => ({ ...prev, page: prev.page - 1 })) }}
                  disabled={pagination.page === 1}
                  className={`flex items-center px-4 py-2 rounded-lg transition duration-300 ${
                    pagination.page === 1
                      ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
                      : 'bg-accent text-white hover:bg-red-700'
                  }`}
                >
                  <span className="text-lg font-bold mr-2">«</span>
                  Previous
                </button>

                {/* Page indicator */}
                <span className="text-gray-600 font-medium px-4">
                  Page {pagination.page} of {pagination.totalPages}
                </span>

                <button
                  type="button"
                  onClick={(e) => { e.preventDefault(); setPagination(prev => ({ ...prev, page: prev.page + 1 })) }}
                  disabled={pagination.page === pagination.totalPages}
                  className={`flex items-center px-4 py-2 rounded-lg transition duration-300 ${
                    pagination.page === pagination.totalPages
                      ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
                      : 'bg-accent text-white hover:bg-red-700'
                  }`}
                >
                  Next
                  <span className="text-lg font-bold ml-2">»</span>
                </button>
              </div>
            </div>
          )}
        </>
      )}

      {/* Edit Modal */}
      {showEditModal && editingSermon && (
        <div className="fixed inset-0 z-50 flex items-center justify-center">
          {/* Backdrop */}
          <div className="fixed inset-0 bg-black/50 backdrop-blur-md" />
          {/* Modal content */}
          <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-4 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center p-4 border-b sticky top-0 bg-white">
              <h2 className="text-xl font-bold">Edit Sermon</h2>
              <button
                onClick={() => setShowEditModal(false)}
                className="text-gray-500 hover:text-gray-700"
              >
                <X className="h-6 w-6" />
              </button>
            </div>

            <form onSubmit={handleUpdate} className="p-4">
              {/* Error/Success Messages */}
              {error && (
                <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 rounded-lg">
                  {error}
                </div>
              )}

              {success && (
                <div className="mb-4 p-3 bg-green-50 border border-green-200 text-green-700 rounded-lg">
                  {success}
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Title */}
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Sermon Title *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.title}
                    onChange={(e) => setFormData(prev => ({ ...prev, title: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    placeholder="Enter sermon title"
                  />
                </div>

                {/* Speaker */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Speaker *
                  </label>
                  <input
                    type="text"
                    required
                    value={formData.speaker}
                    onChange={(e) => setFormData(prev => ({ ...prev, speaker: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    placeholder="Enter speaker name"
                  />
                </div>

                {/* Date */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Date *
                  </label>
                  <input
                    type="date"
                    required
                    value={formData.date}
                    onChange={(e) => setFormData(prev => ({ ...prev, date: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                  />
                </div>

                {/* Series */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Series
                  </label>
                  <input
                    type="text"
                    value={formData.series}
                    onChange={(e) => setFormData(prev => ({ ...prev, series: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    placeholder="e.g., Faith in Action"
                  />
                </div>

                {/* Bible Passage */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Bible Passage
                  </label>
                  <input
                    type="text"
                    value={formData.biblePassage}
                    onChange={(e) => setFormData(prev => ({ ...prev, biblePassage: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    placeholder="e.g., John 3:16"
                  />
                </div>

                {/* Description */}
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Description
                  </label>
                  <textarea
                    value={formData.description}
                    onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    rows={4}
                    placeholder="Optional description of the sermon"
                  />
                </div>

                {/* Tags */}
                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Tags
                  </label>
                  <input
                    type="text"
                    value={formData.tags}
                    onChange={(e) => setFormData(prev => ({ ...prev, tags: e.target.value }))}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-accent focus:border-transparent"
                    placeholder="Separate tags with commas (faith, hope, love)"
                  />
                  <p className="text-sm text-gray-500 mt-1">
                    Separate multiple tags with commas
                  </p>
                </div>
              </div>

              {/* Submit Buttons */}
              <div className="flex justify-end space-x-4 mt-6 pt-4 border-t">
                <button
                  type="button"
                  onClick={() => setShowEditModal(false)}
