import { NextRequest, NextResponse } from 'next/server'
import { supabaseAdmin } from '@/lib/supabase'
import { getCurrentAdmin } from '@/lib/auth'
import { donationsDb } from '@/lib/db'

export async function GET(request: NextRequest) {
  try {
    // Admin auth check
    const admin = getCurrentAdmin(request)
    if (!admin || (admin.role !== 'super_admin' && admin.role !== 'admin')) {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 })
    }

    const { searchParams } = new URL(request.url)
    const year = searchParams.get('year') || new Date().getFullYear().toString()
    const fromDate = `${year}-01-01`
    const toDate = `${parseInt(year) + 1}-01-01`

    // Fetch completed donations for the year
    const donations = await donationsDb.getAll().then(donations => 
      donations.filter(d => 
        d.status === 'completed' &&
        new Date(d.created_at) >= new Date(fromDate) &&
        new Date(d.created_at) < new Date(toDate)
      )
    )

    if (!donations || donations.length === 0) {
      return NextResponse.json({ 
        success: true, 
        data: {
          totalReceipts: 0,
          totalExpenditure: 0, 
          netSurplus: 0,
          receiptBreakdown: [],
          expenditureBreakdown: [],
          quarterlyData: [],
          count: 0
        }
      })
    }

    // Aggregate totals
    const totalReceipts = donations.reduce((sum, d) => sum + (d.amount || 0), 0)
    const uniqueDonors = new Set(donations.map(d => d.donor_email).filter(Boolean)).size

    // Receipt breakdown by donation_type (or payment_channel if no type)
    const typeBreakdown = donations.reduce((acc, d) => {
      const type = d.donation_type || d.payment_channel || 'other'
      acc[type] = (acc[type] || 0) + (d.amount || 0)
      return acc
    }, {} as Record<string, number>)

    const receiptBreakdown = Object.entries(typeBreakdown)
      .map(([category, amount]) => ({
        category,
        amount,
        percentage: (amount / totalReceipts) * 100
      }))
      .slice(0, 4) // Top 4

    // Monthly data grouped by year
    const monthlyData = donations.reduce((acc, d) => {
      const date = new Date(d.created_at)
      const yearKey = date.getFullYear().toString()
      const monthKey = date.toLocaleDateString('en-US', { month: 'short', year: 'numeric' })

      if (!acc[yearKey]) acc[yearKey] = {}
      if (!acc[yearKey][monthKey]) acc[yearKey][monthKey] = { receipts: 0, count: 0 }

      acc[yearKey][monthKey].receipts += (d.amount || 0)
      acc[yearKey][monthKey].count += 1

      return acc
    }, {} as Record<string, Record<string, { receipts: number; count: number }>>)

    // Flatten for API response
    const monthlyBreakdown = Object.entries(monthlyData).flatMap(([year, months]) => 
      Object.entries(months).map(([month, stats]) => ({
        year: parseInt(year),
        month,
        receipts: stats.receipts,
        count: stats.count
      }))
    )

    // Expenditure placeholder
    const expenditureBreakdown = [
      { category: 'Ministry Activities', amount: totalReceipts * 0.4, percentage: 40 },
      { category: 'Outreach & Missions', amount: totalReceipts * 0.25, percentage: 25 },
      { category: 'Church Operations', amount: totalReceipts * 0.2, percentage: 20 },
      { category: 'Building Fund', amount: totalReceipts * 0.15, percentage: 15 }
    ]

    const reportData = {
      totalReceipts,
      totalExpenditure: 0,
      netSurplus: totalReceipts,
      receiptBreakdown,
      expenditureBreakdown,
      monthlyData: monthlyBreakdown,
      count: donations.length,
      uniqueDonors,
      year: parseInt(year),
      currency: 'GHS'
    }

    return NextResponse.json({ success: true, data: reportData })

  } catch (error) {
    console.error('Financial report API error:', error)
    return NextResponse.json({ success: false, error: 'Server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import connectDB from '@/lib/database'
import Admin from '@/models/Admin'
import { 
  setAuthCookies, 
  generateToken, 
  generateRefreshToken, 
  getCurrentAdmin,
  verifyRefreshToken
} from '@/lib/auth'

// Error codes for better debugging
export const ERROR_CODES = {
  MISSING_CREDENTIALS: 'AUTH_001',
  INVALID_CREDENTIALS: 'AUTH_002',
  ACCOUNT_DEACTIVATED: 'AUTH_003',
  DATABASE_ERROR: 'AUTH_004',
  TOKEN_ERROR: 'AUTH_005',
  INTERNAL_ERROR: 'AUTH_500'
} as const

export type ErrorCode = typeof ERROR_CODES[keyof typeof ERROR_CODES]

// Rate limiting store (in production, use Redis)
const loginAttempts = new Map<string, { count: number; lastAttempt: number }>()

// Clear rate limiter on server start (development)
console.log('🗑️  Rate limiter initialized - attempts cleared on restart')

/**
 * Check and update login attempts for rate limiting
 */
function checkRateLimit(ip: string): { allowed: boolean; remaining: number } {
  const now = Date.now()
  const windowMs = 15 * 60 * 1000 // 15 minutes
  const maxAttempts = 5

  // In development mode, be more lenient - only 3 failed attempts per minute per IP
  const isDevMode = !process.env.MONGODB_URI || process.env.NODE_ENV === 'development'
  const effectiveMaxAttempts = isDevMode ? 10 : maxAttempts
  const effectiveWindowMs = isDevMode ? 60 * 1000 : windowMs

  const attempt = loginAttempts.get(ip)

  if (!attempt || now - attempt.lastAttempt > effectiveWindowMs) {
    // New window - reset count
    loginAttempts.set(ip, { count: 1, lastAttempt: now })
    console.log(`🔐 Rate limit: New window for ${ip}, attempts reset`)
    return { allowed: true, remaining: effectiveMaxAttempts - 1 }
  }

  if (attempt.count >= effectiveMaxAttempts) {
    console.log(`🔐 Rate limit: Blocked ${ip}, max attempts reached (${attempt.count})`)
    return { allowed: false, remaining: 0 }
  }

  // Increment count
  attempt.count++
  attempt.lastAttempt = now
  console.log(`🔐 Rate limit: ${ip} now has ${attempt.count}/${effectiveMaxAttempts} attempts`)
  return { allowed: true, remaining: effectiveMaxAttempts - attempt.count }
}

/**
 * Clean old rate limit entries
 */
function cleanupRateLimit() {
  const now = Date.now()
  const windowMs = 15 * 60 * 1000

  for (const [ip, attempt] of loginAttempts.entries()) {
    if (now - attempt.lastAttempt > windowMs) {
      loginAttempts.delete(ip)
    }
  }
}

// Run cleanup every hour
if (typeof setInterval !== 'undefined') {
  setInterval(cleanupRateLimit, 60 * 60 * 1000)
}

export async function POST(request: NextRequest) {
  const startTime = Date.now()
  const clientIp = request.headers.get('x-forwarded-for') || 'unknown'

  try {
    const body = await request.json().catch(() => ({}))
    const { email, password } = body

    // Validate input
    if (!email || !password) {
      return NextResponse.json(
        { 
          success: false, 
          error: 'Email and password are required',
          code: ERROR_CODES.MISSING_CREDENTIALS
        },
        { status: 400 }
      )
    }

    // Check rate limit
    const rateLimit = checkRateLimit(clientIp)
    if (!rateLimit.allowed) {
      return NextResponse.json(
        { 
          success: false, 
          error: 'Too many login attempts. Please try again in 15 minutes.',
          code: ERROR_CODES.INVALID_CREDENTIALS
        },
        { status: 429 }
      )
    }

    // Normalize email
    const normalizedEmail = email.toLowerCase().trim()

    // Development mode: Check for hardcoded credentials first
    const isDevMode = !process.env.MONGODB_URI || process.env.NODE_ENV === 'development'

    if (isDevMode && normalizedEmail === 'admin@elshaddai.com' && password === 'admin123') {
      console.log('🔐 Development mode login successful with hardcoded credentials')

      const token = generateToken({
        adminId: 'dev-admin-id',
        email: normalizedEmail,
        role: 'super_admin',
        name: 'Admin',
        profileImage: ''
      })

      const refreshToken = generateRefreshToken('dev-admin-id')

      return setAuthCookies(token, refreshToken, 'Login successful (development mode)')
    }

    // Try database connection for production or when admin exists
    let dbConnection = null
    try {
      dbConnection = await connectDB()
    } catch (dbError) {
      console.error('Database connection error:', dbError)
      // If no database and not dev mode, credentials fail
      if (!isDevMode) {
        return NextResponse.json(
          { 
            success: false, 
            error: 'Unable to verify credentials. Please try again later.',
            code: ERROR_CODES.DATABASE_ERROR
          },
          { status: 503 }
        )
      }
    }

    if (!dbConnection) {
      // No database connection - only dev mode credentials work
      console.log('⚠️  No database connection, only dev mode credentials accepted')
      return NextResponse.json(
        { 
          success: false, 
          error: 'Invalid credentials',
          code: ERROR_CODES.INVALID_CREDENTIALS
        },
        { status: 401 }
      )
    }

    // Find admin by email
    const admin = await Admin.findOne({ email: normalizedEmail })

    if (!admin) {
      console.log(`🔐 Login failed: No admin found for ${normalizedEmail}`)
      return NextResponse.json(
        { 
          success: false, 
          error: 'Invalid credentials',
          code: ERROR_CODES.INVALID_CREDENTIALS
        },
        { status: 401 }
      )
    }

    // Check if admin is active
    if (!admin.isActive) {
      console.log(`🔐 Login failed: Account deactivated for ${normalizedEmail}`)
      return NextResponse.json(
        { 
          success: false, 
          error: 'Account is deactivated. Please contact a super administrator.',
          code: ERROR_CODES.ACCOUNT_DEACTIVATED
        },
        { status: 403 }
      )
    }

    // Verify password with error handling
    let isMatch = false
    try {
      isMatch = await admin.comparePassword(password)
    } catch (bcryptError) {
      console.error('Password comparison error:', bcryptError)
      return NextResponse.json(
        { 
          success: false, 
          error: 'An error occurred during authentication. Please try again.',
          code: ERROR_CODES.INTERNAL_ERROR
        },
        { status: 500 }
      )
    }

    if (!isMatch) {
      console.log(`🔐 Login failed: Invalid password for ${normalizedEmail}`)
      return NextResponse.json(
        { 
          success: false, 
          error: 'Invalid credentials',
          code: ERROR_CODES.INVALID_CREDENTIALS
        },
        { status: 401 }
      )
    }

    // Update last login
    try {
      admin.lastLogin = new Date()
      await admin.save()
    } catch (updateError) {
      // Non-critical error - login still succeeds
      console.warn('Failed to update lastLogin:', updateError)
    }

    // Generate tokens
    const token = generateToken({
      adminId: admin._id.toString(),
      email: admin.email,
      role: admin.role,
      name: admin.name,
      profileImage: admin.profileImage || ''
    })

    const refreshToken = generateRefreshToken(admin._id.toString())

    const duration = Date.now() - startTime
    console.log(`🔐 Login successful for ${normalizedEmail} (${duration}ms)`)

    // Set cookies and return response
    return setAuthCookies(token, refreshToken, 'Login successful')

  } catch (error) {
    console.error('Login error:', error)

    // Handle specific error types
    if (error instanceof SyntaxError) {
      return NextResponse.json(
        { 
          success: false, 
          error: 'Invalid request body',
          code: ERROR_CODES.INTERNAL_ERROR
        },
        { status: 400 }
      )
    }

    return NextResponse.json(
      { 
        success: false, 
        error: 'Internal server error. Please try again later.',
        code: ERROR_CODES.INTERNAL_ERROR
      },
      { status: 500 }
    )
  }
}

