// DELETE - Cancel a booking
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const confirmationNumber = searchParams.get('confirmationNumber');
    const email = searchParams.get('email');

    if (!confirmationNumber || !email) {
      return NextResponse.json(
        { success: false, error: 'Confirmation number and email are required' },
        { status: 400 }
      );
    }

    // Try Supabase first
    if (isDbConfigured()) {
      try {
        const bookings = await counsellingBookingsDb.getAll()
        const booking = bookings.find(b => 
          b.preferred_counsellor === confirmationNumber || 
          b.email === email
        )

        if (booking) {
          await counsellingBookingsDb.update(booking.id, {
            status: 'cancelled'
          })

          // Send cancellation email
          try {
            await sendCancellationEmail({
              id: booking.id,
              createdAt: booking.created_at,
              firstName: '',
              lastName: '',
              email: booking.email,
              phone: booking.phone || '',
              country: '',
              city: '',
              counsellorId: booking.preferred_counsellor || '',
              bookingType: 'online',
              preferredDate: booking.booking_date,
              preferredTime: booking.time_slot,
              sessionDuration: 60,
              topic: booking.issue_type || '',
              notes: booking.notes || '',
              status: 'cancelled',
              confirmationNumber,
              isPaid: false,
            });
          } catch (emailError) {
            console.error('Error sending cancellation email:', emailError);
          }

          return NextResponse.json({
            success: true,
            message: 'Booking cancelled successfully',
            isSupabaseMode: true,
            isInMemoryMode: false
          });
        }
      } catch (dbError) {
        console.error('[Counselling API] Database error:', dbError)
      }
    }

    // Fallback to in-memory
    const bookingIndex = inMemoryBookings.findIndex(b => b.confirmationNumber === confirmationNumber);

    if (bookingIndex === -1) {
      return NextResponse.json(
        { success: false, error: 'Booking not found' },
        { status: 404 }
      );
    }

    const booking = inMemoryBookings[bookingIndex];

    if (booking.email !== email) {
      return NextResponse.json(
        { success: false, error: 'Email does not match booking' },
        { status: 403 }
      );
    }

    // Update booking status to cancelled
    inMemoryBookings[bookingIndex].status = 'cancelled';

    // Send cancellation email
    try {
      await sendCancellationEmail({
        id: booking.id,
        createdAt: booking.createdAt.toISOString(),
        firstName: booking.firstName,
        lastName: booking.lastName,
        email: booking.email,
        phone: booking.phone || '',
        country: booking.country || '',
        city: booking.city || '',
        counsellorId: booking.counsellorId,
        bookingType: booking.bookingType,
        preferredDate: booking.preferredDate,
        preferredTime: booking.preferredTime,
        sessionDuration: booking.sessionDuration,
        topic: booking.topic,
        notes: booking.notes || '',
        teamsMeetingUrl: booking.teamsMeetingUrl,
        teamsJoinUrl: booking.teamsJoinUrl,
        status: inMemoryBookings[bookingIndex].status,
        confirmationNumber: booking.confirmationNumber,
        isPaid: booking.isPaid,
      });
    } catch (emailError) {
      console.error('Error sending cancellation email:', emailError);
    }

    return NextResponse.json({
      success: true,
      message: 'Booking cancelled successfully',
      isSupabaseMode: false,
      isInMemoryMode: true,
      fallback: true
    });
  } catch (error) {
    console.error('Error cancelling booking:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to cancel booking' },
      { status: 500 }
    );
  }
}

function validateFormData(data: BookingFormData): string[] {
  const errors: string[] = [];

  if (!data.firstName?.trim()) {
    errors.push('First name is required');
  }

  if (!data.lastName?.trim()) {
    errors.push('Last name is required');
  }

  if (!data.email?.trim()) {
    errors.push('Email is required');
  } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
    errors.push('Please enter a valid email address');
  }

  if (!data.phone?.trim()) {
    errors.push('Phone number is required');
  }

  if (!data.country) {
    errors.push('Country is required');
  }

  if (!data.counsellorId) {
    errors.push('Please select a counsellor');
  }

  if (!data.preferredDate) {
    errors.push('Please select a preferred date');
  }

  if (!data.preferredTime) {
    errors.push('Please select a preferred time');
  }

  if (!data.topic?.trim()) {
    errors.push('Please specify a topic for your session');
  }

  return errors;
}

interface AvailableSlot {
  id: string;
  counsellorId: string;
  date: string;
  startTime: string;
  endTime: string;
  isAvailable: boolean;
}

function generateAvailableSlots(counsellors: Array<{id: string; availability: Array<{dayOfWeek: number; startTime: string; endTime: string}>}>): AvailableSlot[] {
  const slots: AvailableSlot[] = [];
  const today = new Date();

  // Generate slots for the next 14 days
  for (let dayOffset = 1; dayOffset <= 14; dayOffset++) {
    const date = new Date(today);
    date.setDate(today.getDate() + dayOffset);
    const dateStr = date.toISOString().split('T')[0];

    // Only show weekdays (Monday to Friday)
    const dayOfWeek = date.getDay();
    if (dayOfWeek === 0 || dayOfWeek === 6) {
      continue;
    }

    for (const counsellor of counsellors) {
      const availability = counsellor.availability.find((a: { dayOfWeek: number }) => a.dayOfWeek === dayOfWeek);
      if (!availability) {
        continue;
      }

      const [startHour, startMin] = availability.startTime.split(':').map(Number);
      const [endHour, endMin] = availability.endTime.split(':').map(Number);

      const startMinutes = startHour * 60 + startMin;
      const endMinutes = endHour * 60 + endMin;

      for (let time = startMinutes; time < endMinutes; time += 30) {
        const hour = Math.floor(time / 60);
        const minute = time % 60;

        const startTime = `${hour.toString().padStart(2, '0')}:${minute.toString().padStart(2, '0')}`;
        const endHour = Math.floor((time + 30) / 60);
        const endMinute = (time + 30) % 60;
        const endTime = `${endHour.toString().padStart(2, '0')}:${endMinute.toString().padStart(2, '0')}`;

        const isAvailable = Math.random() > 0.3;

        slots.push({
          id: `${counsellor.id}-${dateStr}-${startTime}`,
          counsellorId: counsellor.id,
          date: dateStr,
          startTime,
          endTime,
          isAvailable,
        });
      }
    }
  }

  return slots;
}

import { NextRequest, NextResponse } from 'next/server';
import { v4 as uuidv4 } from 'uuid';

// In-memory storage for counselors
interface StoredCounsellor {
  id: string;
  name: string;
  title: string;
  specialization: string[];
  bio: string;
  imageUrl: string;
  email: string;
  phone?: string;
  availability: Availability[];
  isOnline: boolean;
  isInPerson: boolean;
  yearsOfExperience: number;
  rating: number;
  reviewCount: number;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}

interface Availability {
  dayOfWeek: number;
  startTime: string;
  endTime: string;
}

// NO MOCK DATA - Empty initial state for admin-created counsellors only
const inMemoryCounsellors: StoredCounsellor[] = [];

// GET - Fetch all active counselors
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const includeInactive = searchParams.get('includeInactive') === 'true';

    let counsellors = inMemoryCounsellors;

    if (!includeInactive) {
      counsellors = counsellors.filter(c => c.isActive);
    }

    return NextResponse.json({
      success: true,
      data: {
        counsellors,
        total: counsellors.length,
      },
    });
  } catch (error) {
    console.error('Error fetching counselors:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to fetch counselors' },
      { status: 500 }
    );
  }
}

// POST - Create a new counselor
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();

    // Validate required fields
    const requiredFields = ['name', 'title', 'bio', 'email', 'specialization'];
    const missingFields = requiredFields.filter(field => !body[field]);

    if (missingFields.length > 0) {
      return NextResponse.json(
        { success: false, error: `Missing required fields: ${missingFields.join(', ')}` },
        { status: 400 }
      );
    }

    // Generate ID
    const id = `counsellor-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    // Create new counselor
    const newCounsellor: StoredCounsellor = {
      id,
      name: body.name,
      title: body.title,
      specialization: body.specialization || [],
      bio: body.bio,
      imageUrl: body.imageUrl || '',
      email: body.email,
      phone: body.phone || '',
      availability: body.availability || [],
      isOnline: body.isOnline ?? true,
      isInPerson: body.isInPerson ?? true,
      yearsOfExperience: body.yearsOfExperience || 0,
      rating: 0,
      reviewCount: 0,
      isActive: true,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    inMemoryCounsellors.push(newCounsellor);

    return NextResponse.json({
      success: true,
      data: newCounsellor,
      message: 'Counsellor created successfully',
    });
  } catch (error) {
    console.error('Error creating counselor:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to create counselor' },
      { status: 500 }
    );
  }
}

// PUT - Update a counselor
export async function PUT(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'Counsellor ID is required' },
        { status: 400 }
      );
    }

    const body = await request.json();

    // Find the counselor
    const index = inMemoryCounsellors.findIndex(c => c.id === id);

    if (index === -1) {
      return NextResponse.json(
        { success: false, error: 'Counsellor not found' },
        { status: 404 }
      );
    }

    // Update counselor
    const updatedCounsellor: StoredCounsellor = {
      ...inMemoryCounsellors[index],
      name: body.name ?? inMemoryCounsellors[index].name,
      title: body.title ?? inMemoryCounsellors[index].title,
      specialization: body.specialization ?? inMemoryCounsellors[index].specialization,
      bio: body.bio ?? inMemoryCounsellors[index].bio,
      imageUrl: body.imageUrl ?? inMemoryCounsellors[index].imageUrl,
      email: body.email ?? inMemoryCounsellors[index].email,
      phone: body.phone ?? inMemoryCounsellors[index].phone,
      availability: body.availability ?? inMemoryCounsellors[index].availability,
      isOnline: body.isOnline ?? inMemoryCounsellors[index].isOnline,
      isInPerson: body.isInPerson ?? inMemoryCounsellors[index].isInPerson,
      yearsOfExperience: body.yearsOfExperience ?? inMemoryCounsellors[index].yearsOfExperience,
      isActive: body.isActive ?? inMemoryCounsellors[index].isActive,
      updatedAt: new Date(),
    };

    inMemoryCounsellors[index] = updatedCounsellor;

    return NextResponse.json({
      success: true,
      data: updatedCounsellor,
      message: 'Counsellor updated successfully',
    });
  } catch (error) {
    console.error('Error updating counselor:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to update counselor' },
      { status: 500 }
    );
  }
}

// DELETE - Delete (deactivate) a counselor
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const id = searchParams.get('id');

    if (!id) {
      return NextResponse.json(
        { success: false, error: 'Counsellor ID is required' },
        { status: 400 }
      );
    }

    // Find the counselor
    const index = inMemoryCounsellors.findIndex(c => c.id === id);

    if (index === -1) {
      return NextResponse.json(
        { success: false, error: 'Counsellor not found' },
        { status: 404 }
      );
    }

    // Soft delete - set isActive to false
    inMemoryCounsellors[index].isActive = false;
    inMemoryCounsellors[index].updatedAt = new Date();

    return NextResponse.json({
      success: true,
      message: 'Counsellor deleted successfully',
    });
  } catch (error) {
    console.error('Error deleting counselor:', error);
    return NextResponse.json(
      { success: false, error: 'Failed to delete counselor' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server'
import connectDB from '@/lib/database'
import Event, { IEvent } from '@/models/Event'

const TIMEOUT_MS = 5000

// GET - Fetch all events for calendar display
export async function GET(request: NextRequest) {
  const controller = new AbortController()
  const timeoutId = setTimeout(() => controller.abort(), TIMEOUT_MS)

  try {
    const dbConnection = await connectDB()

    if (!dbConnection) {
      clearTimeout(timeoutId)
      return NextResponse.json(
        { error: 'Database connection not available' },
        { status: 503 }
      )
    }

    const searchParams = request.nextUrl.searchParams
    const year = searchParams.get('year')
    const month = searchParams.get('month')
    const category = searchParams.get('category')

    // Build query - fetch all published events
    const query: Record<string, unknown> = { isPublished: true }

    // Filter by year if provided
    if (year) {
      const yearStart = new Date(`${year}-01-01`)
      const yearEnd = new Date(`${year}-12-31`)
      query.date = { $gte: yearStart, $lte: yearEnd }
    }

    // Filter by month if provided (requires year as well)
    if (year && month) {
      const monthIndex = parseInt(month) - 1 // JavaScript months are 0-indexed
      const startDate = new Date(parseInt(year), monthIndex, 1)
      const endDate = new Date(parseInt(year), monthIndex + 1, 0, 23, 59, 59)
      query.date = { $gte: startDate, $lte: endDate }
    }

    if (category && category !== 'all') {
      query.category = category
    }

    const events = await Event.find(query)
      .sort({ date: 1 })
      .lean()
      .maxTimeMS(TIMEOUT_MS - 1000)

    // Transform events to calendar-friendly format
    const calendarEvents = events.map(event => {
      const eventDate = new Date(event.date)
      return {
        _id: event._id.toString(),
        title: event.title,
        description: event.description,
        date: eventDate.toISOString().split('T')[0], // YYYY-MM-DD format
        time: event.time,
        location: event.location,
        category: event.category,
        recurring: event.recurring,
        dateObj: eventDate
      }
    })

    // Group events by date for easier calendar rendering
    const eventsByDate: Record<string, typeof calendarEvents[0][]> = {}
    calendarEvents.forEach(event => {
      if (!eventsByDate[event.date]) {
        eventsByDate[event.date] = []
      }
      eventsByDate[event.date].push(event)
    })

    clearTimeout(timeoutId)

    return NextResponse.json({
      success: true,
      events: calendarEvents,
      eventsByDate,
      count: calendarEvents.length
    })

  } catch (error) {
    clearTimeout(timeoutId)
    if (error instanceof Error && error.name === 'AbortError') {
      console.error('Calendar events API request timed out')
      return NextResponse.json(
        { error: 'Request timed out. Database connection may be slow.' },
        { status: 503 }
      )
    }
    console.error('Error fetching calendar events:', error)
    return NextResponse.json(
      { error: 'Failed to fetch calendar events' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import connectDB, { isDatabaseConnected } from '@/lib/database'
import Settings from '@/models/Settings'
import { getInMemoryYouTubeSettings } from '@/lib/youtubeStorage'
import { checkChannelLiveStatus, extractChannelId, getChannelIdFromUsername } from '@/lib/youtube'

// In-memory cache for live stream status
let cachedLiveStatus: {
  isLive: boolean
  streamInfo: {
    title: string
    viewerCount: number
    scheduledStartTime?: string
    actualStartTime?: string
    videoId?: string
    embedUrl?: string
  } | null
  liveVideoId?: string
  lastUpdate: Date | null
} | null = null
let lastCacheUpdate: Date | null = null
const CACHE_DURATION_MS = 30 * 1000 // 30 seconds cache for live status

interface YouTubeConfigType {
  channelId?: string
  channelUrl?: string
  apiKey?: string
}

/**
 * YouTube Live API - Simplified approach
 * 
 * IMPORTANT: YouTube Data API's liveBroadcasts endpoint now requires OAuth2 authentication,
 * not just an API key. Since we're using the YouTube iframe embed which handles live detection
 * automatically, we can rely on time-based detection instead of the API.
 * 
 * This approach:
 * 1. Uses the live stream embed URL (YouTube handles live detection internally)
 * 2. Falls back to time-based service detection when API is unavailable
 * 3. Removes dependency on YouTube Data API for live status
 */

// GET - Fetch live stream status
export async function GET(request: NextRequest) {
  try {
    const searchParams = request.nextUrl.searchParams
    const forceRefresh = searchParams.get('refresh') === 'true'

    // Check cache first
    const now = new Date()
    const cacheExpired = !lastCacheUpdate || 
      (now.getTime() - lastCacheUpdate.getTime()) > CACHE_DURATION_MS

    if (!forceRefresh && cachedLiveStatus && !cacheExpired) {
      return NextResponse.json({
        success: true,
        isLive: cachedLiveStatus.isLive,
        streamInfo: cachedLiveStatus.streamInfo,
        cached: true,
        lastUpdate: lastCacheUpdate,
        method: 'cache'
      })
    }

    // Try to connect to database for settings
    let settings: Record<string, unknown> | null = null

    // First, try to connect to the database
    const dbConnection = await connectDB()

    // Check both dbConnection and connection readiness
    const isReady = await isDatabaseConnected()

    if (dbConnection && isReady) {
      try {
        settings = await Settings.findOne().lean() as Record<string, unknown> | null
      } catch (error) {
        console.error('Database query error:', error)
      }
    } else if (!dbConnection) {
      console.warn('Database connection not available, using fallback mode')
    } else {
      console.warn('Database connection not ready yet, using fallback mode')
    }

    // Get YouTube configuration from database or in-memory
    const youtubeConfig = (settings?.youtube as YouTubeConfigType) || getInMemoryYouTubeSettings()

    // Get channel ID - try config first, then environment variable
    let channelId = youtubeConfig?.channelId || process.env.NEXT_PUBLIC_YOUTUBE_CHANNEL_ID || ''
    const apiKey = youtubeConfig?.apiKey || process.env.YOUTUBE_API_KEY || ''
    const channelUrl = youtubeConfig?.channelUrl || ''

    // Check if YouTube is configured
    if (!channelId && !channelUrl) {
      // Return fallback based on time if not configured
      const fallbackStatus = getTimeBasedLiveStatus()
      return NextResponse.json({
        success: true,
        isLive: fallbackStatus.isLive,
        configured: false,
        channelId: null,
        fallback: fallbackStatus,
        method: 'time-based',
        message: 'Add YouTube channel ID to settings to enable live stream embed'
      })
    }

    // Resolve channel ID from URL if needed
    if (!channelId && channelUrl) {
      // Try to extract channel ID from URL
      const extractedId = extractChannelId(channelUrl)
      if (extractedId) {
        channelId = extractedId
      } else if (apiKey) {
        // For @username URLs, need to use API to get channel ID
        const atMatch = channelUrl.match(/youtube\.com\/@([a-zA-Z0-9_-]+)/)
        const cMatch = channelUrl.match(/youtube\.com\/c\/([a-zA-Z0-9_-]+)/)
        const userMatch = channelUrl.match(/youtube\.com\/user\/([a-zA-Z0-9_-]+)/)

        const usernameMatch = atMatch || cMatch || userMatch

        if (usernameMatch) {
          console.log(`[Live API] Resolving channel ID from username: ${usernameMatch[1]}`)
          channelId = await getChannelIdFromUsername(usernameMatch[1], apiKey) || ''
        }
      }
    }

    // Check if we have an API key to check actual live status
    let isLive = false
    let liveVideoId: string | undefined
    let liveVideoTitle: string | undefined
    let viewerCount = 0

    if (channelId && apiKey) {
      // Use YouTube API to check for actual live streams
      console.log(`[Live API] Checking YouTube API for live streams on channel: ${channelId}`)
      const liveStatus = await checkChannelLiveStatus(channelId, apiKey)

      if (liveStatus.isLive && liveStatus.liveVideo) {
        isLive = true
        liveVideoId = liveStatus.liveVideo.id
        liveVideoTitle = liveStatus.liveVideo.title
        viewerCount = parseInt(liveStatus.liveVideo.viewCount) || 0
        console.log(`[Live API] Found live stream: ${liveVideoTitle}`)
      } else {
        console.log('[Live API] No live stream found on YouTube')
      }
    } else {
      console.log('[Live API] No API key available, using time-based detection')
    }

    // Fall back to time-based detection if no actual live stream found
    const timeBasedStatus = getTimeBasedLiveStatus()

    // If no actual live stream, use time-based detection
    if (!isLive && timeBasedStatus.isLive) {
      isLive = true
      liveVideoTitle = getServiceTitle(timeBasedStatus.serviceType || '')
      viewerCount = estimateViewerCount(timeBasedStatus.serviceType || '')
    }

    // Update cache
    cachedLiveStatus = {
      isLive,
      streamInfo: isLive ? {
        title: liveVideoTitle || getServiceTitle(timeBasedStatus.serviceType || ''),
        viewerCount,
        scheduledStartTime: timeBasedStatus.scheduledTime,
        videoId: liveVideoId,
        embedUrl: liveVideoId ? `https://www.youtube.com/embed/${liveVideoId}` : undefined
      } : null,
      liveVideoId,
      lastUpdate: now
    }
    lastCacheUpdate = now

    return NextResponse.json({
      success: true,
      isLive,
      configured: true,
      channelId,
      streamInfo: cachedLiveStatus.streamInfo,
      cached: false,
      lastUpdate: now,
      method: apiKey ? 'youtube-api' : 'time-based',
      message: apiKey 
        ? (isLive ? 'Live stream detected on YouTube' : 'No live stream found on YouTube')
        : 'Using time-based detection. Add API key to check actual YouTube live status.'
    })

  } catch (error) {
    console.error('Error fetching live stream status:', error)

    // Always return a valid response with fallback
    const fallbackStatus = getTimeBasedLiveStatus()
    return NextResponse.json({
      success: true,
      isLive: fallbackStatus.isLive,
      fallback: fallbackStatus,
      method: 'error-fallback',
      error: error instanceof Error ? error.message : 'Unknown error'
    }, { status: 200 })
  }
}

// Helper function to estimate viewer count based on service type
function estimateViewerCount(serviceType: string): number {
  switch (serviceType) {
    case 'sunday-morning':
      return 450 // Peak attendance
    case 'sunday-evening':
      return 300
    case 'wednesday':
      return 200
    case 'friday-youth':
      return 250
    default:
      return 150
  }
}

// Get service title based on service type
function getServiceTitle(serviceType: string): string {
  switch (serviceType) {
    case 'sunday-morning':
      return 'Sunday Morning Service'
    case 'sunday-evening':
      return 'Sunday Evening Service'
    case 'wednesday':
      return 'Wednesday Bible Study'
    case 'friday-youth':
      return 'Friday Youth Service'
    default:
      return 'Live Service'
  }
}

// Time-based live status detection
function getTimeBasedLiveStatus(): {
  isLive: boolean
  serviceType?: string
  scheduledTime?: string
} {
  const now = new Date()
  const day = now.getDay()
  const hour = now.getHours()
  const minute = now.getMinutes()
  const currentMinutes = hour * 60 + minute

  // Sunday Services (9 AM - 12 PM and 11 AM - 2 PM)
  if (day === 0) {
    // First service: 9 AM - 12 PM
    if (currentMinutes >= 9 * 60 && currentMinutes < 12 * 60) {
      return { isLive: true, serviceType: 'sunday-morning', scheduledTime: '9:00 AM' }
    }
    // Second service: 11 AM - 2 PM
    if (currentMinutes >= 11 * 60 && currentMinutes < 14 * 60) {
      return { isLive: true, serviceType: 'sunday-evening', scheduledTime: '11:00 AM' }
    }
  }

  // Wednesday Bible Study (7 PM - 9 PM)
  if (day === 3) {
    if (currentMinutes >= 19 * 60 && currentMinutes < 21 * 60) {
      return { isLive: true, serviceType: 'wednesday', scheduledTime: '7:00 PM' }
    }
  }

  // Friday Youth Service (7 PM - 10 PM)
  if (day === 5) {
    if (currentMinutes >= 19 * 60 && currentMinutes < 22 * 60) {
      return { isLive: true, serviceType: 'friday-youth', scheduledTime: '7:00 PM' }
    }
  }

  return { isLive: false }
}

// POST - Force refresh live status (for admin use)
export async function POST(request: NextRequest) {
  try {
    // Clear cache to force fresh fetch
    cachedLiveStatus = null
    lastCacheUpdate = null

    // Trigger a fresh GET request
    const url = new URL(request.url)
    url.searchParams.set('refresh', 'true')

    const response = await fetch(url.toString(), {
      method: 'GET',
      headers: request.headers
    })

    const data = await response.json()

    return NextResponse.json(data)

  } catch (error) {
    console.error('Error refreshing live stream status:', error)
    return NextResponse.json({
      success: false,
      error: 'Failed to refresh live stream status'
    }, { status: 500 })
  }
}

// DELETE - Clear cache
export async function DELETE() {
  cachedLiveStatus = null
  lastCacheUpdate = null

  return NextResponse.json({
    success: true,
    message: 'Live stream cache cleared'
  })
}

