        )}

        {/* Sermon Grid */}
        {!loading && (
          <>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {sermons.map((sermon) => (
                <SermonCard 
                  key={sermon._id || sermon.id} 
                  sermon={sermon} 
                  source={sermon.source}
