// Helper component for cross decorations
function CrossDecoration({ position, delay }: { position: 'topLeft' | 'topRight' | 'bottomLeft' | 'bottomRight', delay: number }) {
  const positions: Record<string, string> = {
    topLeft: 'top-6 left-6',
    topRight: 'top-6 right-6',
    bottomLeft: 'bottom-6 left-6',
    bottomRight: 'bottom-6 right-6'
  }

  return (
    <motion.div
      className={`absolute text-2xl text-white/30 ${positions[position]}`}
      initial={{ scale: 0, rotate: -45 }}
      animate={{ scale: 1, rotate: 0 }}
      transition={{ delay, duration: 0.7, type: 'spring' }}
    >
      ✞
    </motion.div>
  )
}

'use client';

import React, { useState, useMemo } from 'react';
import { ChevronLeft, ChevronRight, Clock, Check } from 'lucide-react';
import { TimeSlot } from '@/types/counselling';
import { formatTimeForDisplay } from '@/types/counselling';

interface TimeSlotPickerProps {
  slots: TimeSlot[];
  selectedDate: string;
  selectedTime: string;
  onDateChange: (date: string) => void;
  onTimeChange: (time: string) => void;
  disabled?: boolean;
}

export default function TimeSlotPicker({
  slots,
  selectedDate,
  selectedTime,
  onDateChange,
  onTimeChange,
  disabled = false,
}: TimeSlotPickerProps) {
  const [currentWeekStart, setCurrentWeekStart] = useState(() => {
    const today = new Date();
    const dayOfWeek = today.getDay();
    // Start from today or the previous Monday
    const start = new Date(today);
    start.setDate(today.getDate() - dayOfWeek + 1);
    return start;
  });

  // Generate dates for the next 2 weeks (weekdays only)
  const availableDates = useMemo(() => {
    const dates: Date[] = [];
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    for (let i = 1; i <= 14; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      const dayOfWeek = date.getDay();
      // Skip weekends (0 = Sunday, 6 = Saturday)
      if (dayOfWeek !== 0 && dayOfWeek !== 6) {
        dates.push(date);
      }
    }
    return dates;
  }, []);

  // Group slots by date
  const slotsByDate = useMemo(() => {
    const grouped: Record<string, TimeSlot[]> = {};
    slots.forEach((slot) => {
      if (!grouped[slot.date]) {
        grouped[slot.date] = [];
      }
      if (slot.isAvailable) {
        grouped[slot.date].push(slot);
      }
    });
    // Sort slots by time
    Object.keys(grouped).forEach((date) => {
      grouped[date].sort((a, b) => a.startTime.localeCompare(b.startTime));
    });
    return grouped;
  }, [slots]);

  // Get available times for selected date
  const availableTimes = selectedDate ? slotsByDate[selectedDate] || [] : [];

  // Format date for display
  const formatDate = (date: Date): string => {
    return date.toISOString().split('T')[0];
  };

  const displayDate = (dateStr: string): string => {
    const date = new Date(dateStr + 'T00:00:00');
    return date.toLocaleDateString('en-US', {
      weekday: 'short',
      month: 'short',
      day: 'numeric',
    });
  };

  // Navigate weeks
  const goToPreviousWeek = () => {
    const newStart = new Date(currentWeekStart);
    newStart.setDate(currentWeekStart.getDate() - 7);
    setCurrentWeekStart(newStart);
  };

  const goToNextWeek = () => {
    const newStart = new Date(currentWeekStart);
    newStart.setDate(currentWeekStart.getDate() + 7);
    setCurrentWeekStart(newStart);
  };

  // Get dates for current week view
  const currentWeekDates = useMemo(() => {
    const dates: Date[] = [];
    for (let i = 0; i < 5; i++) {
      const date = new Date(currentWeekStart);
      date.setDate(currentWeekStart.getDate() + i);
      // Check if it's a weekday
      if (date.getDay() !== 0 && date.getDay() !== 6) {
        dates.push(date);
      }
    }
    return dates;
  }, [currentWeekStart]);

  return (
    <div className="space-y-4">
      {/* Date Navigation */}
      <div className="flex items-center justify-between mb-4">
        <button
          type="button"
          onClick={goToPreviousWeek}
          className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          disabled={disabled}
        >
          <ChevronLeft size={20} className="text-gray-600" />
        </button>
        <span className="font-semibold text-gray-800">
          {currentWeekStart.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
        </span>
        <button
          type="button"
          onClick={goToNextWeek}
          className="p-2 hover:bg-gray-100 rounded-full transition-colors"
          disabled={disabled}
        >
          <ChevronRight size={20} className="text-gray-600" />
        </button>
      </div>

      {/* Date Selection */}
      <div className="grid grid-cols-5 gap-2">
        {currentWeekDates.map((date) => {
          const dateStr = formatDate(date);
          const isSelected = selectedDate === dateStr;
          const hasSlots = slotsByDate[dateStr] && slotsByDate[dateStr].length > 0;
          const isPast = new Date(dateStr) < new Date(new Date().toISOString().split('T')[0]);

          return (
            <button
              key={dateStr}
              type="button"
              onClick={() => {
                if (hasSlots && !isPast) {
                  onDateChange(dateStr);
                }
              }}
              disabled={!hasSlots || isPast || disabled}
              className={`p-3 rounded-lg border-2 transition-all ${
                isSelected
                  ? 'border-[#C8102E] bg-[#C8102E] text-white'
                  : hasSlots && !isPast
                  ? 'border-gray-200 hover:border-[#C8102E] bg-white text-gray-800'
                  : 'border-gray-100 bg-gray-50 text-gray-400 cursor-not-allowed'
              }`}
            >
              <div className="text-xs font-medium">
                {date.toLocaleDateString('en-US', { weekday: 'short' })}
              </div>
              <div className="text-lg font-bold">{date.getDate()}</div>
              {hasSlots && !isPast && !isSelected && (
                <div className="text-xs text-green-600 mt-1">
                  {slotsByDate[dateStr].length} slots
                </div>
              )}
            </button>
          );
        })}
      </div>

      {/* Time Slots */}
      {selectedDate && (
        <div className="mt-6">
          <h4 className="font-semibold text-gray-800 mb-3 flex items-center gap-2">
            <Clock size={18} />
            Available Times for {displayDate(selectedDate)}
          </h4>

          {availableTimes.length > 0 ? (
            <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
              {availableTimes.map((slot) => {
                const isSelected = selectedTime === slot.startTime;
                return (
                  <button
                    key={slot.id}
                    type="button"
                    onClick={() => onTimeChange(slot.startTime)}
                    disabled={disabled}
                    className={`p-3 rounded-lg border-2 transition-all ${
                      isSelected
                        ? 'border-[#C8102E] bg-[#C8102E] text-white'
                        : 'border-gray-200 hover:border-[#003399] bg-white text-gray-800'
                    }`}
                  >
                    <div className="flex items-center justify-center gap-1">
                      {isSelected && <Check size={14} />}
                      <span className="font-medium">{formatTimeForDisplay(slot.startTime)}</span>
                    </div>
                  </button>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-8 bg-gray-50 rounded-lg">
              <p className="text-gray-500">No available time slots for this date</p>
              <p className="text-sm text-gray-400">Please select another date</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import jwt, { SignOptions, JwtPayload } from 'jsonwebtoken'
import { NextResponse } from 'next/server'

const JWT_SECRET = process.env.JWT_SECRET || 'your-super-secret-jwt-key-change-in-production'
const JWT_EXPIRES_IN = '7d'
const COOKIE_NAME = 'admin_auth_token'

export interface JWTPayload {
  adminId: string
  email: string
  role: string
  name?: string
  profileImage?: string
  iat?: number
  exp?: number
}

// Validate JWT_SECRET at module load time
function validateEnvironment(): void {
  if (!process.env.JWT_SECRET) {
    console.warn('⚠️  WARNING: JWT_SECRET not set in environment variables!')
    console.warn('⚠️  Using default secret which is NOT secure for production!')
    console.warn('⚠️  Please set JWT_SECRET in your .env file for production use.')
  } else if (process.env.JWT_SECRET === 'your-super-secret-jwt-key-change-in-production') {
    console.warn('⚠️  WARNING: JWT_SECRET appears to be the default value!')
    console.warn('⚠️  Please change JWT_SECRET to a unique, secure value.')
  } else {
    console.log('✅ JWT_SECRET is configured properly')
  }
}

// Run validation on module load
validateEnvironment()

/**
 * Generate a JWT token for an admin
 */
export function generateToken(payload: Omit<JWTPayload, 'iat' | 'exp'>): string {
  const options: SignOptions = {
    expiresIn: JWT_EXPIRES_IN
  }
  return jwt.sign(payload, JWT_SECRET, options)
}

/**
 * Generate a refresh token with longer expiration
 */
export function generateRefreshToken(adminId: string): string {
  return jwt.sign(
    { adminId, type: 'refresh' },
    JWT_SECRET + '_refresh',
    { expiresIn: '30d' }
  )
}

/**
 * Verify and decode a JWT token
 */
export function verifyToken(token: string): JWTPayload | null {
  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JWTPayload
    return decoded
  } catch (error) {
    console.error('JWT verification failed:', error)
    return null
  }
}

/**
 * Verify a refresh token
 */
export function verifyRefreshToken(token: string): { adminId: string } | null {
  try {
    const decoded = jwt.verify(token, JWT_SECRET + '_refresh') as { adminId: string; type: string }
    if (decoded.type !== 'refresh') return null
    return { adminId: decoded.adminId }
  } catch (error) {
    console.error('Refresh token verification failed:', error)
    return null
  }
}

/**
 * Check if token is expired and get time remaining
 */
export function getTokenStatus(token: string): { valid: boolean; expired: boolean; timeRemaining?: number } {
  try {
    const decoded = jwt.verify(token, JWT_SECRET, { ignoreExpiration: true }) as JwtPayload
    const now = Math.floor(Date.now() / 1000)

    if (decoded.exp && decoded.exp < now) {
      return { valid: false, expired: true, timeRemaining: 0 }
    }

    const timeRemaining = decoded.exp ? decoded.exp - now : undefined
    return { valid: true, expired: false, timeRemaining }
  } catch (error) {
    return { valid: false, expired: true }
  }
}

/**
 * Create a response with the auth cookie set
 */
export function createAuthResponse(
  data: object,
  message?: string,
  status: number = 200
): NextResponse {
  const response = NextResponse.json({
    success: true,
    ...(message && { message }),
    ...data
  }, { status })

  return response
}

/**
 * Create response with auth cookie for login
 */
export function setAuthCookie(token: string, message?: string): NextResponse {
  const isDev = !process.env.NODE_ENV || process.env.NODE_ENV === 'development'

  const response = NextResponse.json({
    success: true,
    message: message || 'Login successful',
    user: verifyToken(token)
  }, {
    status: 200
  })

  // Use sameSite: 'lax' which works for both development and production
  // 'none' requires secure: true which doesn't work in local development
  response.cookies.set(COOKIE_NAME, token, {
    httpOnly: true,
    secure: !isDev,
    sameSite: 'lax',
    maxAge: 60 * 60 * 24 * 7, // 7 days
    path: '/'
  })

  return response
}

/**
 * Create response with auth and refresh cookies
 */
export function setAuthCookies(token: string, refreshToken: string, message?: string): NextResponse {
  const isDev = !process.env.NODE_ENV || process.env.NODE_ENV === 'development'

  const response = NextResponse.json({
    success: true,
    message: message || 'Login successful',
    user: verifyToken(token)
  }, {
    status: 200
  })

  // Use sameSite: 'lax' which works for both development and production
  // 'none' requires secure: true which doesn't work in local development
  // Set auth token (7 days)
  response.cookies.set(COOKIE_NAME, token, {
    httpOnly: true,
    secure: !isDev,
    sameSite: 'lax',
    maxAge: 60 * 60 * 24 * 7,
    path: '/'
  })

  // Set refresh token (30 days)
  response.cookies.set('admin_refresh_token', refreshToken, {
    httpOnly: true,
    secure: !isDev,
    sameSite: 'lax',
    maxAge: 60 * 60 * 24 * 30,
    path: '/'
  })

  return response
}

/**
 * Clear the auth cookie
 */
export function clearAuthCookie(message?: string): NextResponse {
  const isDev = !process.env.NODE_ENV || process.env.NODE_ENV === 'development'

  const response = NextResponse.json({
    success: true,
    message: message || 'Logged out successfully'
  }, {
    status: 200
  })

  // Use sameSite: 'lax' which works for both development and production
  // Clear auth token
  response.cookies.set(COOKIE_NAME, '', {
    httpOnly: true,
    secure: !isDev,
    sameSite: 'lax',
    maxAge: 0,
    path: '/'
  })

  // Clear refresh token
  response.cookies.set('admin_refresh_token', '', {
    httpOnly: true,
    secure: !isDev,
    sameSite: 'lax',
    maxAge: 0,
    path: '/'
  })

  return response
}

/**
 * Get auth token from cookies
 */
export function getAuthToken(request: Request): string | null {
  // Try to get from cookies header first
  const cookieHeader = request.headers.get('cookie')
  if (cookieHeader) {
    const cookies = cookieHeader.split(';').reduce((acc, cookie) => {
      const [key, value] = cookie.trim().split('=')
      acc[key] = value
      return acc
    }, {} as Record<string, string>)

    if (cookies[COOKIE_NAME]) {
      return cookies[COOKIE_NAME]
    }
  }

  // Fallback: try to get from cookies directly (for Next.js 14+)
  if ('cookies' in request) {
    try {
      const requestWithCookies = request as { cookies?: { get: (name: string) => { value: string } | undefined } }
      return requestWithCookies.cookies?.get(COOKIE_NAME)?.value || null
    } catch {
      return null
    }
  }

  return null
}

/**
 * Get refresh token from cookies
 */
export function getRefreshToken(request: Request): string | null {
  const cookieHeader = request.headers.get('cookie')
  if (cookieHeader) {
    const cookies = cookieHeader.split(';').reduce((acc, cookie) => {
      const [key, value] = cookie.trim().split('=')
      acc[key] = value
      return acc
    }, {} as Record<string, string>)

    return cookies['admin_refresh_token'] || null
  }

  if ('cookies' in request) {
    try {
      const requestWithCookies = request as { cookies?: { get: (name: string) => { value: string } | undefined } }
      return requestWithCookies.cookies?.get('admin_refresh_token')?.value || null
    } catch {
      return null
    }
  }

  return null
}

/**
 * Get current admin from request
 */
export function getCurrentAdmin(request: Request): JWTPayload | null {
  const token = getAuthToken(request)
  if (!token) return null

  return verifyToken(token)
}

