/**
 * YouTube Data API Service
 * Fetches videos from YouTube channels for sermon display
 */

import axios from 'axios'

// YouTube API configuration
const YOUTUBE_API_BASE_URL = 'https://www.googleapis.com/youtube/v3'

export interface YouTubeVideo {
  id: string
  title: string
  description: string
  thumbnailUrl: string
  videoUrl: string
  embedUrl: string
  channelTitle: string
  publishedAt: string
  duration: string
  durationSeconds: number
  viewCount: string
}

export interface YouTubeChannel {
  id: string
  title: string
  description: string
  thumbnailUrl: string
  subscriberCount: string
  videoCount: string
}

/**
 * Extract video ID from various YouTube URL formats
 */
export function extractVideoId(url: string): string | null {
  const patterns = [
    /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([^&\n?#]+)/,
    /^([a-zA-Z0-9_-]{11})$/
  ]

  for (const pattern of patterns) {
    const match = url.match(pattern)
    if (match) {
      return match[1] || match[0]
    }
  }
  return null
}

/**
 * Extract channel ID from YouTube URL
 * Returns the actual channel ID (UC...) or null if URL requires API lookup
 */
export function extractChannelId(url: string): string | null {
  // Direct channel ID format (UC...)
  if (/^[a-zA-Z0-9_-]{22,24}$/.test(url)) {
    return url
  }

  // Extract channel ID from /channel/ URLs (UC...)
  const channelMatch = url.match(/youtube\.com\/channel\/([a-zA-Z0-9_-]+)/)
  if (channelMatch) {
    return channelMatch[1]
  }

  // For @username, /c/, or /user/ URLs, we need to call API to get channel ID
  // Return null so the caller knows to use getChannelIdFromUsername
  return null
}

/**
 * Get channel ID from username using YouTube API
 */
export async function getChannelIdFromUsername(username: string, apiKey: string): Promise<string | null> {
  try {
    const response = await axios.get(`${YOUTUBE_API_BASE_URL}/channels`, {
      params: {
        part: 'id',
        forHandle: username.replace('@', ''),
        key: apiKey
      }
    })

    if (response.data.items && response.data.items.length > 0) {
      return response.data.items[0].id
    }
    return null
  } catch (error) {
    console.error('Error getting channel ID from username:', error)
    return null
  }
}

/**
 * Fetch all playlists from a YouTube channel
 */
export async function fetchChannelPlaylists(
  channelId: string,
  apiKey: string,
  options: {
    maxResults?: number
    pageToken?: string
  } = {}
): Promise<{ playlists: YouTubePlaylist[], nextPageToken: string | null, totalResults: number }> {
  const { maxResults = 50, pageToken } = options

  try {
    const params: Record<string, string | number> = {
      part: 'snippet,contentDetails',
      channelId: channelId,
      maxResults,
      key: apiKey
    }

    if (pageToken) {
      params.pageToken = pageToken
    }

    const response = await axios.get(`${YOUTUBE_API_BASE_URL}/playlists`, {
      params
    })

    const playlists = response.data.items.map((item: {
      id: string
      snippet: { title: string; description: string; thumbnails: { high?: { url?: string }; medium?: { url?: string } } }
      contentDetails: { itemCount: number }
    }) => ({
      id: item.id,
      title: item.snippet.title,
      description: item.snippet.description,
      thumbnailUrl: item.snippet.thumbnails?.high?.url || item.snippet.thumbnails?.medium?.url || '',
      itemCount: item.contentDetails.itemCount
    }))

    return {
      playlists,
      nextPageToken: response.data.nextPageToken || null,
      totalResults: response.data.pageInfo?.totalResults || 0
    }
  } catch (error) {
    console.error('Error fetching channel playlists:', error)
    return { playlists: [], nextPageToken: null, totalResults: 0 }
  }
}

/**
 * Find the sermons playlist from a list of playlists
 * Looks for playlist titles containing "sermon" (case-insensitive)
 */
export function findSermonsPlaylist(playlists: YouTubePlaylist[]): YouTubePlaylist | null {
  // Search for playlists with "sermon" in the title
  const sermonsPlaylist = playlists.find(playlist => 
    playlist.title.toLowerCase().includes('sermon') || 
    playlist.title.toLowerCase().includes('sermons')
  )

  return sermonsPlaylist || null
}

export interface YouTubePlaylist {
  id: string
  title: string
  description: string
  thumbnailUrl: string
  itemCount: number
}

/**
 * Convert YouTube duration format (PT#H#M#S) to human readable
 */
export function formatDuration(duration: string): string {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/)
  if (!match) return duration

  const hours = match[1] ? parseInt(match[1]) : 0
  const minutes = match[2] ? parseInt(match[2]) : 0
  const seconds = match[3] ? parseInt(match[3]) : 0

  const parts = []
  if (hours > 0) parts.push(`${hours}h`)
  if (minutes > 0) parts.push(`${minutes}m`)
  if (seconds > 0 && hours === 0) parts.push(`${seconds}s`)

  return parts.join(' ') || '0s'
}

/**
 * Convert YouTube duration to seconds
 */
export function durationToSeconds(duration: string): number {
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/)
  if (!match) return 0

  const hours = match[1] ? parseInt(match[1]) : 0
  const minutes = match[2] ? parseInt(match[2]) : 0
  const seconds = match[3] ? parseInt(match[3]) : 0

  return hours * 3600 + minutes * 60 + seconds
}

/**
 * YouTube API response interfaces
 */
interface YouTubeAPIResponseItem {
  id?: { videoId?: string } | string
  snippet?: {
    title?: string
    description?: string
    thumbnails?: {
      high?: { url?: string }
      medium?: { url?: string }
      default?: { url?: string }
    }
    channelTitle?: string
    publishedAt?: string
  }
  contentDetails?: {
    duration?: string
    videoId?: string
  }
  statistics?: {
    viewCount?: string
  }
}

/**
 * Transform YouTube API response to our Sermon format
 */
export function transformYouTubeVideo(video: YouTubeAPIResponseItem): YouTubeVideo {
  let videoId = ''
  if (typeof video.id === 'object' && video.id !== null) {
    videoId = video.id.videoId || ''
  } else if (typeof video.id === 'string') {
    videoId = video.id
  }
  const snippet = video.snippet || {}

  return {
    id: videoId,
    title: snippet.title || '',
    description: snippet.description || '',
    thumbnailUrl: snippet.thumbnails?.high?.url || snippet.thumbnails?.medium?.url || snippet.thumbnails?.default?.url || '',
    videoUrl: `https://www.youtube.com/watch?v=${videoId}`,
    embedUrl: `https://www.youtube.com/embed/${videoId}`,
    channelTitle: snippet.channelTitle || '',
    publishedAt: snippet.publishedAt || '',
    duration: video.contentDetails?.duration || '',
    durationSeconds: video.contentDetails?.duration ? durationToSeconds(video.contentDetails.duration) : 0,
    viewCount: video.statistics?.viewCount || '0'
  }
}

/**
 * Fetch channel details from YouTube
 */
export async function fetchChannelDetails(channelId: string, apiKey: string): Promise<YouTubeChannel | null> {
  try {
    const response = await axios.get(`${YOUTUBE_API_BASE_URL}/channels`, {
      params: {
        part: 'snippet,statistics',
        id: channelId,
        key: apiKey
      }
    })

    const channel = response.data.items?.[0]
    if (!channel) return null

    return {
      id: channel.id,
      title: channel.snippet.title,
      description: channel.snippet.description,
      thumbnailUrl: channel.snippet.thumbnails?.high?.url || channel.snippet.thumbnails?.medium?.url || '',
      subscriberCount: channel.statistics?.subscriberCount || '0',
      videoCount: channel.statistics?.videoCount || '0'
    }
  } catch (error) {
    console.error('Error fetching YouTube channel:', error)
    return null
  }
}

/**
 * Fetch latest videos from a YouTube channel with pagination support
 * Optionally fetches from a specific playlist instead of channel uploads
 */
export async function fetchChannelVideos(
  channelId: string,
  apiKey: string,
  options: {
    maxResults?: number
    order?: 'date' | 'viewCount' | 'rating'
    type?: 'video' | 'playlist' | 'all'
    pageToken?: string
    playlistId?: string  // If provided, fetch from this playlist instead of channel uploads
  } = {}
): Promise<{ videos: YouTubeVideo[], nextPageToken: string | null, totalResults: number }> {
  const { maxResults = 50, order = 'date', type = 'video', pageToken, playlistId } = options

  try {
    let uploadsPlaylistId = playlistId

    // If no playlistId provided, get the channel's uploads playlist ID
    if (!uploadsPlaylistId) {
      const channelResponse = await axios.get(`${YOUTUBE_API_BASE_URL}/channels`, {
        params: {
          part: 'contentDetails',
          id: channelId,
          key: apiKey
        }
      })

      const channel = channelResponse.data.items?.[0]
      if (!channel) {
        console.error('Channel not found')
        return { videos: [], nextPageToken: null, totalResults: 0 }
      }

      uploadsPlaylistId = channel.contentDetails.relatedPlaylists?.uploads
      if (!uploadsPlaylistId) {
        console.error('No uploads playlist found')
        return { videos: [], nextPageToken: null, totalResults: 0 }
      }
    }

    // Fetch videos from the playlist (either specified playlist or channel uploads)
    const playlistParams: Record<string, string | number> = {
      part: 'snippet,contentDetails',
      playlistId: uploadsPlaylistId,
      maxResults,
      key: apiKey
    }

    if (pageToken) {
      playlistParams.pageToken = pageToken
    }

    const playlistResponse = await axios.get(`${YOUTUBE_API_BASE_URL}/playlistItems`, {
      params: playlistParams
    })

    const videoIds = playlistResponse.data.items
      .map((item: { contentDetails?: { videoId?: string } }) => item.contentDetails?.videoId || '')
      .filter(Boolean)
      .join(',')

    if (!videoIds) {
      return { 
        videos: [], 
        nextPageToken: playlistResponse.data.nextPageToken || null,
        totalResults: playlistResponse.data.pageInfo?.totalResults || 0
      }
    }

    // Get video details including duration
    const videosResponse = await axios.get(`${YOUTUBE_API_BASE_URL}/videos`, {
      params: {
        part: 'snippet,contentDetails,statistics',
        id: videoIds,
        key: apiKey
      }
    })

    return {
      videos: videosResponse.data.items.map(transformYouTubeVideo),
      nextPageToken: playlistResponse.data.nextPageToken || null,
      totalResults: playlistResponse.data.pageInfo?.totalResults || videosResponse.data.items.length
    }
  } catch (error) {
    console.error('Error fetching YouTube videos:', error)
    return { videos: [], nextPageToken: null, totalResults: 0 }
  }
}

/**
 * Fetch ALL videos from a YouTube channel by looping through all pages
 * Uses pagination to get all available videos
 * Optionally fetches from a specific playlist instead of channel uploads
 */
export async function fetchAllChannelVideos(
  channelId: string,
  apiKey: string,
  options: {
    maxVideos?: number  // Maximum number of videos to fetch (YouTube API limit is 500 per request for playlistItems)
    maxResultsPerPage?: number
    playlistId?: string  // If provided, fetch from this playlist instead of channel uploads
  } = {}
): Promise<YouTubeVideo[]> {
  const { maxVideos = 500, maxResultsPerPage = 50, playlistId } = options

  let allVideos: YouTubeVideo[] = []
  let nextPageToken: string | null = null
  let totalFetched = 0
  let hasMore = true

  // Maximum number of API calls to prevent infinite loops
  const maxIterations = Math.ceil(maxVideos / maxResultsPerPage)

  try {
    while (hasMore && totalFetched < maxVideos && allVideos.length < maxVideos) {
      const iteration = allVideos.length / maxResultsPerPage + 1

      const result = await fetchChannelVideos(channelId, apiKey, {
        maxResults: maxResultsPerPage,
        pageToken: nextPageToken || undefined,
        playlistId: playlistId  // Pass playlistId to fetch from specific playlist
      })

      if (result.videos.length === 0) {
        hasMore = false
        break
      }

      allVideos = [...allVideos, ...result.videos]
      totalFetched = allVideos.length
      nextPageToken = result.nextPageToken

      // Stop if no more pages
      if (!nextPageToken) {
        hasMore = false
      }

      // Safety check for infinite loops
      if (iteration >= maxIterations) {
        console.warn(`Reached maximum iterations (${maxIterations}), stopping pagination`)
        hasMore = false
      }
    }

    // Return only the first maxVideos if we fetched more
    return allVideos.slice(0, maxVideos)
  } catch (error) {
    console.error('Error fetching all YouTube videos:', error)
    return allVideos
  }
}

/**
 * Search for videos on YouTube (alternative method without channel ID)
 */
export async function searchVideos(
  query: string,
  apiKey: string,
  options: {
    maxResults?: number
    order?: 'date' | 'viewCount' | 'relevance'
    channelId?: string
  } = {}
): Promise<YouTubeVideo[]> {
  const { maxResults = 20, order = 'date', channelId } = options

  try {
    const searchParams: Record<string, string | number | boolean | undefined> = {
      part: 'snippet',
      q: query,
      maxResults,
      order,
      type: 'video',
      key: apiKey
    }

    if (channelId) {
      searchParams.channelId = channelId
    }

    const response = await axios.get(`${YOUTUBE_API_BASE_URL}/search`, {
      params: searchParams
    })

    const videoIds = response.data.items
      .map((item: { id?: { videoId?: string } | string }) => {
        const idValue = item.id
        if (typeof idValue === 'object' && idValue !== null) {
          return idValue.videoId || ''
        }
        return idValue || ''
      })
      .filter((id: string) => id.length > 0)
      .join(',')

    if (!videoIds) return []

    // Get video details
    const videosResponse = await axios.get(`${YOUTUBE_API_BASE_URL}/videos`, {
      params: {
        part: 'snippet,contentDetails,statistics',
        id: videoIds,
        key: apiKey
      }
    })

    return videosResponse.data.items.map(transformYouTubeVideo)
  } catch (error) {
    console.error('Error searching YouTube videos:', error)
    return []
  }
}

/**
 * Transform YouTube video to sermon format for frontend
 */
export function youTubeVideoToSermon(video: YouTubeVideo) {
  return {
    id: `youtube_${video.id}`,
    _id: `youtube_${video.id}`,
    title: video.title,
    speaker: video.channelTitle,
    date: new Date(video.publishedAt).toISOString(),
    description: video.description,
    thumbnail: video.thumbnailUrl,
    videoUrl: video.videoUrl,
    embedUrl: video.embedUrl,
    audioUrl: null, // YouTube doesn't provide audio download
    duration: formatDuration(video.duration),
    durationSeconds: video.durationSeconds,
    series: null,
    biblePassage: null,
    tags: ['youtube'],
    isYouTube: true,
    viewCount: video.viewCount
  }
}

/**
 * Get embed HTML for a YouTube video
 */
export function getEmbedHtml(videoId: string, options: {
  autoplay?: boolean
  modestBranding?: boolean
} = {}): string {
  const { autoplay = false, modestBranding = true } = options
  const params = new URLSearchParams({
    autoplay: autoplay ? '1' : '0',
    modestbranding: modestBranding ? '1' : '0',
    rel: '0',
    iv_load_policy: '3'
  })

  return `<iframe 
    width="100%" 
    height="100%" 
    src="https://www.youtube.com/embed/${videoId}?${params.toString()}" 
    frameborder="0" 
    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
    allowfullscreen
  ></iframe>`
}

/**
 * Fetch live streams from a YouTube channel
 * Uses the YouTube Data API search endpoint with eventType=live
 */
export async function fetchLiveStreams(
  channelId: string,
  apiKey: string,
  options: {
    maxResults?: number
  } = {}
): Promise<YouTubeVideo[]> {
  const { maxResults = 5 } = options

  // Validate inputs
  if (!channelId) {
    console.error('fetchLiveStreams: No channelId provided')
    return []
  }

  if (!apiKey) {
    console.error('fetchLiveStreams: No API key provided')
    return []
  }

  try {
    // Use the search endpoint to find live broadcasts from the channel
    const response = await axios.get(`${YOUTUBE_API_BASE_URL}/search`, {
      params: {
        part: 'snippet',
        channelId: channelId,
        eventType: 'live',
        type: 'video',
        maxResults,
        key: apiKey
      }
    })

    if (!response.data.items || response.data.items.length === 0) {
      return []
    }

    // Get video IDs from search results
    const videoIds = response.data.items
      .map((item: { id?: { videoId?: string } }) => item.id?.videoId || '')
      .filter(Boolean)
      .join(',')

    if (!videoIds) {
      return []
    }

    // Get full video details including live streaming info
    const videosResponse = await axios.get(`${YOUTUBE_API_BASE_URL}/videos`, {
      params: {
        part: 'snippet,contentDetails,statistics,liveStreamingDetails',
        id: videoIds,
        key: apiKey
      }
    })

    return videosResponse.data.items.map(transformYouTubeVideo)
  } catch (error) {
    // Log detailed error information for debugging
    if (axios.isAxiosError(error)) {
      console.error('YouTube API Error Details:')
      console.error('- Status:', error.response?.status)
      console.error('- Status Text:', error.response?.statusText)
      console.error('- Response Data:', error.response?.data)
      console.error('- Request URL:', error.config?.url)
      console.error('- Request Params:', error.config?.params)

      // Check for specific error reasons
      const errorData = error.response?.data
      if (errorData?.error) {
        console.error('- Error Code:', errorData.error.code)
        console.error('- Error Message:', errorData.error.message)
        console.error('- Error Domain:', errorData.error.errors?.[0]?.domain)
        console.error('- Error Reason:', errorData.error.errors?.[0]?.reason)
      }
    } else {
      console.error('Error fetching live streams:', error)
    }
    return []
  }
}

/**
 * Check if a YouTube channel has any live streams
 * Returns live stream info if available, null otherwise
 */
export async function checkChannelLiveStatus(
  channelId: string,
  apiKey: string
): Promise<{
  isLive: boolean
  liveVideo?: YouTubeVideo
  error?: string
}> {
  try {
    const liveStreams = await fetchLiveStreams(channelId, apiKey, { maxResults: 1 })

    if (liveStreams.length > 0) {
      return {
        isLive: true,
        liveVideo: liveStreams[0]
      }
    }

    return { isLive: false }
  } catch (error) {
    // Provide more detailed error information
    let errorMessage = 'Unknown error'

    if (axios.isAxiosError(error)) {
      const status = error.response?.status
      const data = error.response?.data

      if (status === 400) {
        errorMessage = 'Bad request - API key may be invalid or missing required permissions'
      } else if (status === 401) {
        errorMessage = 'Unauthorized - API key is invalid'
      } else if (status === 403) {
        errorMessage = 'Forbidden - API key may be expired or quota exceeded'
      } else if (status === 404) {
        errorMessage = 'Not found - Channel does not exist'
      } else {
        errorMessage = data?.error?.message || error.message
      }

      console.error('YouTube API error in checkChannelLiveStatus:', {
        status,
        message: errorMessage,
        data
      })
    } else if (error instanceof Error) {
      errorMessage = error.message
      console.error('Error checking channel live status:', errorMessage)
    }

    return {
      isLive: false,
      error: errorMessage
    }
  }
}

